    '창세기': 'gen', '출애굽기': 'exo', '레위기': 'lev', '민수기': 'num', '신명기': 'deu',
    '여호수아': 'jos', '사사기': 'jdg', '룻기': 'rut', '사무엘상': '1sa', '사무엘하': '2sa',
