    '오바댜': 'oba', '요나': 'jon', '미가': 'mic', '나훔': 'nam', '하박국': 'hab',
    '스바냐': 'zep', '학개': 'hag', '스가랴': 'zec', '말라기': 'mal',
    '마태복음': 'mat', '마가복음': 'mrk', '누가복음': 'luk', '요한복음': 'jhn', '사도행전': 'act',
    '로마서': 'rom', '고린도전서': '1co', '고린도후서': '2co', '갈라디아서': 'gal', '에베소서': 'eph',
