    '요한삼서': '3jn', '유다서': 'jud', '요한계시록': 'rev'
};

const alternativeMaps = {
    'sng': 'sos', 'jol': 'joe', 'nam': 'nah', 'jud': 'jude', 'jdg': 'judg'
};

async function checkUrl(url) {
    return new Promise((resolve) => {
        https.get(url, (res) => {
            let data = '';
            res.on('data', chunk => data += chunk);
            res.on('end', () => {
                if (data.includes('Bible book not found')) resolve(false);
                else resolve(true);
            });
        }).on('error', () => resolve(false));
    });
}

(async () => {
    for (const [name, abbr] of Object.entries(KOR_BOOK_MAP)) {
        const url = `https://ibibles.net/quote.php?kor-${abbr}/1:1`;
        const ok = await checkUrl(url);
        if (!ok) {
            console.log(`Failed: ${name} (${abbr})`);

            // Try alternatives
            if (alternativeMaps[abbr]) {
                const altUrl = `https://ibibles.net/quote.php?kor-${alternativeMaps[abbr]}/1:1`;
                const altOk = await checkUrl(altUrl);
                if (altOk) {
                    console.log(`  -> Fixed: ${name} should be ${alternativeMaps[abbr]}`);
                }
            } else if (abbr === 'jdg') {
                const altUrl = `https://ibibles.net/quote.php?kor-judg/1:1`;
                const altOk = await checkUrl(altUrl);
                if (altOk) console.log(`  -> Fixed: 사사기 should be judg`);
            }
        }
    }
})();

