import { google, embeddingModel } from '@/lib/ai-client';
import { streamText, embed } from 'ai';
import { createClient } from '@supabase/supabase-js';

// Allow streaming responses up to 30 seconds
export const maxDuration = 30;

export async function POST(req: Request) {
    const { messages, userId } = await req.json();
    const lastMessage = messages[messages.length - 1];

    // 1. Setup Supabase Client
    const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
    const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;
    const supabase = createClient(supabaseUrl, supabaseServiceKey);

    // 2. Generate Embedding for the Query
    const { embedding } = await embed({
        model: embeddingModel,
        value: lastMessage.content,
    });

    // 3. Retrieve Context (Vector Search)
    // Call the 'match_journals' RPC function
    const { data: similarJournals } = await supabase.rpc('match_journals', {
        query_embedding: embedding,
        match_threshold: 0.5, // Sensitivity
        match_count: 5,       // Top 5 relevant journals
        p_user_id: userId
    });

    // 4. Construct Context String
    let contextBlock = "";
    if (similarJournals && similarJournals.length > 0) {
        contextBlock = `
Relevant Past Journals from User:
${similarJournals.map((j: any) => `- "${j.content}"`).join('\n')}
    `.trim();
    }

    // 5. System Prompt
    const systemPrompt = `
You are "Rhema", a spiritual companion and digital twin for the user's faith journey.
You are gentle, encouraging, and deeply rooted in biblical wisdom.
Use the user's past journal entries (provided below) to give personalized, context-aware responses.
If the user mentions a struggle they wrote about before, acknowledge it.
Keep your responses concise, warm, and spiritually uplifting. 
Do not be preachy. Be like a wise friend walking alongside them.

**Special Instruction for Prayers:**
If the user asks you to pray for them, or if the input is a raw prayer (e.g., "Help me God, I am tired"), 
you MUST generate a poetic, psalm-like prayer.
In this case, start your response with "기도문:" followed by the poetic prayer. 
After the prayer, you can add a brief encouraging message.

${contextBlock}
  `.trim();

    // 6. Generate Response
    const result = streamText({
        model: google('gemini-1.5-pro-latest') as any,
        system: systemPrompt,
        messages,
    });

    return (result as any).toDataStreamResponse();
}

import { embed } from 'ai';
import { google, embeddingModel } from '@/lib/ai-client';
import { createClient } from '@/lib/supabase-client'; // Note: server-side client needed?
import { createClient as createSupabaseClient } from '@supabase/supabase-js';
import { NextResponse } from 'next/server';

// Server-side Supabase client with Service Role Key for writing embeddings
// (If using RLS with auth user, standard client might work, but safer to use service role for background tasks)
// However, here we are in an API route called by the client (potentially).
// If called by client, we should use the user's session.

export async function POST(req: Request) {
    try {
        const { journalId, content, userId } = await req.json();

        if (!journalId || !content || !userId) {
            return NextResponse.json({ error: 'Missing required fields' }, { status: 400 });
        }

        // 1. Generate Embedding
        const { embedding } = await embed({
            model: embeddingModel,
            value: content,
        });

        // 2. Save to Supabase
        // We need a client that can write to journal_embeddings.
        // Ideally use the authenticated user's client if passing cookie, 
        // but for simplicity in this prototype, we'll assume the request is authorized 
        // or use a service role client if we trust the input (Be careful in production).

        // Better: Verify session
        const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
        const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY; // Need to add this to env?
        const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;

        // For now, let's try using the anon key and RLS. 
        // The RLS policy "Users can insert own embeddings" requires auth.uid() = user_id.
        // So we need to create a client with the user's access token if possible,
        // OR just use service role key for now to bypass RLS for this specific operation
        // assuming the API route is protected or internal.

        // Since we don't have easy access to the user's access token in this simple request body 
        // (unless we pass it or use cookies), let's use the Service Role Key for the RAG background task.
        // CHECK: Does the user have SUPABASE_SERVICE_ROLE_KEY?
        // If not, we must rely on client-side call or RLS with cookie.

        // Let's assume we use the Service Role Key for "backend" tasks.
        const supabase = createSupabaseClient(supabaseUrl, supabaseServiceKey || supabaseAnonKey);

        const { error } = await supabase.from('journal_embeddings').upsert({
            journal_id: journalId,
            user_id: userId,
            embedding: embedding,
            created_at: new Date().toISOString()
        });

        if (error) {
            console.error("Supabase embedding insert error:", error);
            return NextResponse.json({ error: error.message }, { status: 500 });
        }

        return NextResponse.json({ success: true });
    } catch (error) {
        console.error("Embedding generation failed:", error);
        return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
    }
}

"use client";

import { useEffect, useState } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { SmartCard } from '@/components/ui/smart-card';
import { Users, Loader2 } from 'lucide-react';
import { Suspense } from 'react';

function InviteHandler() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const [status, setStatus] = useState<'loading' | 'success' | 'error'>('loading');
    const [groupCode, setGroupCode] = useState<string | null>(null);

    useEffect(() => {
        const handleInvite = async () => {
            // 1. Get Code from URL
            const code = searchParams.get('code');

            // 2. Handle 'Deep Link' check
            // If opened via Custom Scheme (bible365://invite?code=...), logic matches.
            // If opened via Web (https://...), logic matches.

            if (code) {
                // Determine if code is encrypted (Phase 6.2)
                // For backward compatibility, we check if it looks like an old ID or new code.
                // But for now, let's assume all new links use the raw ID until we switch UI to use encrypt.
                // Wait, I should import decrypt.

                // Let's lazy load decrypt to avoid bundling issues if any
                const { decryptInviteCode } = await import('@/lib/crypto');

                // Attempt decrypt
                let finalGroupId = decryptInviteCode(code);

                // Fallback: If decrypt fails, maybe it's a legacy raw code?
                // Or if decrypt returns null/empty
                if (!finalGroupId) {
                    finalGroupId = code; // Assume raw for legacy/fallback
                }

                // eslint-disable-next-line react-hooks/set-state-in-effect
                setGroupCode(finalGroupId);
                localStorage.setItem('bible_group_id', finalGroupId);
                setStatus('success');

                // 3. Redirect
                // If we are in the Native App -> Go Home
                // If we are on Web -> Offer to "Open App" or "Go Home"

                // Detection logic
                const isNative = window.navigator.userAgent.includes('Capacitor');

                if (isNative) {
                    setTimeout(() => router.push('/'), 1000);
                } else {
                    // Web Fallback: Try to open via Custom Scheme
                    window.location.href = `bible365://invite?code=${code}`;

                    // Stay on page to show "Download App" or "Open Web"
                    setStatus('success'); // Keep success state but maybe change message
                }
            } else {
                setStatus('error');
                setTimeout(() => router.push('/'), 2000);
            }
        };

        handleInvite();
    }, [searchParams, router]);

    return (
        <div className="min-h-screen flex items-center justify-center bg-background p-4">
            <SmartCard variant="elevated" className="max-w-sm w-full p-8 text-center space-y-6">
                <div className="w-20 h-20 rounded-full bg-primary/10 flex items-center justify-center mx-auto">
                    {status === 'loading' ? (
                        <Loader2 className="animate-spin text-primary" size={40} />
                    ) : (
                        <Users className="text-primary" size={40} />
                    )}
                </div>

                <div className="space-y-2">
                    <h1 className="text-2xl font-serif font-black">
                        {status === 'loading' && "초대장 확인 중..."}
                        {status === 'success' && "그룹 참여 완료! 🎉"}
                        {status === 'error' && "유효하지 않은 링크"}
                    </h1>
                    <p className="text-sm text-muted-foreground">
                        {status === 'loading' && "잠시만 기다려주세요."}
                        {status === 'success' && `${groupCode} 그룹으로 이동합니다.`}
                        {status === 'error' && "메인 화면으로 이동합니다."}
                    </p>
                </div>
            </SmartCard>
        </div>
    );
}

export default function InvitePage() {
    return (
        <Suspense fallback={<div className="min-h-screen flex items-center justify-center"><Loader2 className="animate-spin" /></div>}>
            <InviteHandler />
        </Suspense>
    );
}

"use client";

import { ErrorBoundary } from "react-error-boundary";
import { Button } from "@/components/ui/button";
import { AlertTriangle, RefreshCcw, Home } from "lucide-react";
import { useRouter } from "next/navigation";

interface AppErrorBoundaryProps {
    children: React.ReactNode;
}

function ErrorFallback({ error, resetErrorBoundary }: { error: any; resetErrorBoundary: () => void }) {
    const router = useRouter();

    return (
        <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-background text-foreground animate-in fade-in duration-500">
            <div className="max-w-md w-full text-center space-y-8">
                {/* Icon with Ring Animation */}
                <div className="relative mx-auto w-24 h-24 flex items-center justify-center">
                    <div className="absolute inset-0 bg-red-500/10 rounded-full animate-ping opacity-75"></div>
                    <div className="relative z-10 bg-background rounded-full p-4 border border-red-500/20 shadow-xl">
                        <AlertTriangle className="w-10 h-10 text-red-500" />
                    </div>
                </div>

                {/* Text Content */}
                <div className="space-y-4">
                    <h1 className="text-3xl font-bold tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-red-500 to-orange-500">
                        문제 발생
                    </h1>
                    <p className="text-muted-foreground leading-relaxed">
                        예기치 않은 오류가 발생했습니다.<br />
                        잠시 후 다시 시도해 주세요.
                    </p>
                    {process.env.NODE_ENV === 'development' && (
                        <div className="p-4 rounded-lg bg-muted/50 text-left overflow-auto max-h-48 text-xs font-mono border border-border/50">
                            {error.message}
                        </div>
                    )}
                </div>

                {/* Actions */}
                <div className="flex flex-col gap-3 sm:flex-row justify-center">
                    <Button
                        onClick={resetErrorBoundary}
                        size="lg"
                        className="rounded-full gap-2 shadow-lg shadow-primary/20"
                    >
                        <RefreshCcw size={18} />
                        다시 시도
                    </Button>
                    <Button
                        variant="outline"
                        size="lg"
                        onClick={() => {
                            resetErrorBoundary();
                            router.push('/');
                        }}
                        className="rounded-full gap-2"
                    >
                        <Home size={18} />
                        홈으로 이동
                    </Button>
                </div>

                <p className="text-xs text-muted-foreground/50 pt-8">
                    Error Code: 500 | System Protection Active
                </p>
            </div>
        </div>
    );
}

export function AppErrorBoundary({ children }: AppErrorBoundaryProps) {
    return (
        <ErrorBoundary
            FallbackComponent={ErrorFallback}
            onReset={() => {
                // Reset the state of your app so the error doesn't happen again
                console.log("Error Boundary Reset");
            }}
            onError={(error, info) => {
                // Log to your error reporting service (e.g., Sentry)
                console.error("Uncaught error:", error, info);
            }}
        >
            {children}
        </ErrorBoundary>
    );
}

