"use client";

import { BibleReadingPlan } from "@/types/bible";
import { Check, BookOpen, PenLine, X } from "lucide-react";
import { useState, useMemo, useEffect } from "react";
import { cn } from "@/lib/utils";
import { generateStructuredKeywords } from "@/lib/bible-utils";
import { BibleService } from "@/lib/bible-service";
import AmenParticles from "./effects/AmenParticles";
import JournalView from "./JournalView";
import ReflectionModal from "./ReflectionModal";
import { useBibleStore } from "@/store/useBibleStore";

interface BibleCardProps {
    plan: BibleReadingPlan;
    isCompleted: boolean;
    onToggle: (id: number) => void;
    onTextClick?: () => void;
    videoDuration?: number | null;
    fontSize?: 'small' | 'medium' | 'large';
    streakDisplayMode?: 'day' | 'progress';
    isFocused?: boolean;
    onFocusToggle?: () => void;
}

type Translation = 'KRV' | 'NIV' | 'NLT';

const FONT_SIZES = {
    small: { title: 'text-2xl', body: 'text-xs', keyword: 'text-[10px]' },
    medium: { title: 'text-3xl', body: 'text-sm', keyword: 'text-xs' },
    large: { title: 'text-4xl', body: 'text-base', keyword: 'text-sm' },
};

const CATEGORY_COLORS: Record<string, { bg: string; text: string; border: string; darkBg: string; darkText: string; darkBorder: string }> = {
    '모세오경': { bg: 'bg-rose-50', text: 'text-rose-700', border: 'border-rose-200', darkBg: 'dark:bg-rose-950/30', darkText: 'dark:text-rose-300', darkBorder: 'dark:border-rose-800/50' },
    '역사서': { bg: 'bg-emerald-50', text: 'text-emerald-700', border: 'border-emerald-200', darkBg: 'dark:bg-emerald-950/30', darkText: 'dark:text-emerald-300', darkBorder: 'dark:border-emerald-800/50' },
    '시가서': { bg: 'bg-sky-50', text: 'text-sky-700', border: 'border-sky-200', darkBg: 'dark:bg-sky-950/30', darkText: 'dark:text-sky-300', darkBorder: 'dark:border-sky-800/50' },
    '대선지서': { bg: 'bg-violet-50', text: 'text-violet-700', border: 'border-violet-200', darkBg: 'dark:bg-violet-950/30', darkText: 'dark:text-violet-300', darkBorder: 'dark:border-violet-800/50' },
    '소선지서': { bg: 'bg-purple-50', text: 'text-purple-700', border: 'border-purple-200', darkBg: 'dark:bg-purple-950/30', darkText: 'dark:text-purple-300', darkBorder: 'dark:border-purple-800/50' },
    '복음서': { bg: 'bg-amber-50', text: 'text-amber-700', border: 'border-amber-200', darkBg: 'dark:bg-amber-950/30', darkText: 'dark:text-amber-300', darkBorder: 'dark:border-amber-800/50' },
    '바울서신': { bg: 'bg-orange-50', text: 'text-orange-700', border: 'border-orange-200', darkBg: 'dark:bg-orange-950/30', darkText: 'dark:text-orange-300', darkBorder: 'dark:border-orange-800/50' },
    '일반서신': { bg: 'bg-teal-50', text: 'text-teal-700', border: 'border-teal-200', darkBg: 'dark:bg-teal-950/30', darkText: 'dark:text-teal-300', darkBorder: 'dark:border-teal-800/50' },
    '요한계시록': { bg: 'bg-indigo-50', text: 'text-indigo-700', border: 'border-indigo-200', darkBg: 'dark:bg-indigo-950/30', darkText: 'dark:text-indigo-300', darkBorder: 'dark:border-indigo-800/50' },
};

function getCategoryStyle(category: string) {
    const match = Object.entries(CATEGORY_COLORS).find(([key]) => category.includes(key));
    if (match) return match[1];
    return { bg: 'bg-primary/5', text: 'text-primary', border: 'border-primary/20', darkBg: 'dark:bg-primary/10', darkText: 'dark:text-primary/90', darkBorder: 'dark:border-primary/30' };
}

export default function BibleCard({ plan, isCompleted, onToggle, onTextClick, videoDuration, fontSize = 'medium', streakDisplayMode = 'day', isFocused = false, onFocusToggle }: BibleCardProps) {
    const fs = FONT_SIZES[fontSize];
    const [loading, setLoading] = useState(false);
    const [showParticles, setShowParticles] = useState(false);
    const [showJournal, setShowJournal] = useState(false);
    const [showReflection, setShowReflection] = useState(false);
    const { addJournal } = useBibleStore();
    // Parallel reading removed for Home Screen compaction

    const [showKeywordsSetting, setShowKeywordsSetting] = useState(true);
    const [requireReflection, setRequireReflection] = useState(true);

    useEffect(() => {
        if (typeof window !== 'undefined') {
            setShowKeywordsSetting(localStorage.getItem('bible_show_keywords') !== 'false');
            setRequireReflection(localStorage.getItem('bible_require_reflection') !== 'false');

            const handleSettingsChange = () => {
                setShowKeywordsSetting(localStorage.getItem('bible_show_keywords') !== 'false');
                setRequireReflection(localStorage.getItem('bible_require_reflection') !== 'false');
            };

            window.addEventListener('bible_settings_changed', handleSettingsChange);
            return () => window.removeEventListener('bible_settings_changed', handleSettingsChange);
        }
    }, []);

    const keywords = useMemo(() => generateStructuredKeywords(plan.verses), [plan.verses]);

    const handleToggle = () => {
        if (!isCompleted) {
            if (requireReflection) {
                setShowReflection(true);
            } else {
                setLoading(true);
                setTimeout(() => {
                    onToggle(plan.id);
                    setLoading(false);
                    setShowParticles(true);
                    setTimeout(() => setShowParticles(false), 2000);
                }, 300);
            }
        } else {
            // uncheck
            onToggle(plan.id);
        }
    };

    const handleReflectionComplete = async (answer: string, rhemaVerse?: string) => {
        setShowReflection(false);
        setLoading(true);

        // Save the reflection as a quick journal entry
        if (answer.trim()) {
            await addJournal({
                plan_id: plan.id,
                content: `[오늘의 은혜]\n${answer}`,
                mood: 'prayer',
                rhema_verse: rhemaVerse
            });
        }

        setTimeout(() => {
            onToggle(plan.id);
            setLoading(false);
            setShowParticles(true);
            setTimeout(() => setShowParticles(false), 2000);
        }, 300);
    };

    return (
        <div className={cn("relative group perspective-1000 transition-all duration-700 z-50", isFocused ? "scale-[1.02]" : "")}>
            {/* Card Container - The Page */}
            <div
                className={cn(
                    "relative overflow-hidden rounded-[2.5rem] transition-all duration-700 p-8",
                    "border backdrop-blur-3xl shadow-2xl",
                    isFocused
                        ? "bg-white/90 dark:bg-black/80 border-white/40 dark:border-white/20 shadow-primary/20 min-h-[50vh] flex flex-col justify-center"
                        : "bg-white/60 dark:bg-black/50 border-white/20 dark:border-white/10 shadow-black/5",
                    isCompleted ? "shadow-gold ring-1 ring-accent/30" : ""
                )}
            >
                {/* Expand / Focus Toggle Button */}
                {onFocusToggle && (
                    <button
                        onClick={(e) => { e.stopPropagation(); onFocusToggle(); }}
                        className="absolute top-6 right-6 p-2 rounded-full bg-black/5 dark:bg-white/10 hover:bg-black/10 dark:hover:bg-white/20 transition-colors z-20 text-foreground/50"
                    >
                        {isFocused ? <X size={20} /> : <BookOpen size={20} />}
                    </button>
                )}

                <div className="flex flex-col items-center text-center gap-6 relative z-10 w-full h-full justify-center">

                    {/* Header Badge & Category Group */}
                    <div className="flex flex-col items-center gap-2">
                        <div className={cn(
                            "flex items-center gap-2 px-4 py-1.5 rounded-full border transition-colors duration-500 shadow-sm",
                            isCompleted
                                ? "bg-accent/10 border-accent/20 text-black dark:text-white"
                                : "bg-black text-white dark:bg-zinc-800 dark:border-zinc-700 dark:text-zinc-300" // Always readable
                        )}>
                            <BookOpen size={12} strokeWidth={2.5} />
                            <span className="text-[11px] font-bold tracking-widest uppercase">
                                {streakDisplayMode === 'progress' ? `${plan.day_of_year}/365일` : `${plan.day_of_year}일차`}
                            </span>
                        </div>
                        {(() => {
                            const catStyle = getCategoryStyle(plan.category || '성경 본문');
                            return (
                                <span className={cn(
                                    "text-[11px] font-bold tracking-widest px-4 py-1.5 rounded-full border shadow-sm",
                                    catStyle.bg, catStyle.text, catStyle.border,
                                    catStyle.darkBg, catStyle.darkText, catStyle.darkBorder
                                )}>
                                    {plan.category || "성경 본문"}
                                </span>
                            );
                        })()}
                    </div>



                    {/* Main Title - Serif & Sacred (Clickable to read) */}
                    <div
                        className="space-y-4 py-4 w-full flex flex-col items-center cursor-pointer active:opacity-70 transition-opacity"
                        onClick={isFocused ? onTextClick : onFocusToggle}
                    >
                        <div className="space-y-2 text-center">
                            <h2 className={cn(
                                `font-serif ${fs.title} font-black tracking-tighter leading-tight transition-all duration-700`,
                                isCompleted ? "text-accent" : "text-foreground",
                                isFocused ? "text-5xl md:text-6xl my-4" : ""
                            )}>
                                {plan.title}
                            </h2>
                        </div>

                        <div className="flex flex-col items-center gap-1">
                            <span className={`text-sm font-medium text-foreground/60 font-sans tracking-wide`}>
                                오늘의 말씀 • 약 {videoDuration ? videoDuration : (plan.reading_time?.replace('mins', '') || "15")}분 소요
                            </span>
                            <span className="text-xs text-muted-foreground/50 font-medium mt-1">
                                {isFocused ? '클릭하여 말씀 읽기 ➔' : '누르면 집중 모드로 전환됩니다'}
                            </span>
                        </div>
                    </div>

                    {/* Daily Keywords */}
                    {showKeywordsSetting && (
                        <div className="flex flex-col items-center justify-center gap-1.5 pt-2">
                            {(() => {
                                const defaults = keywords.filter(k => !k.isPsalm);
                                const psalms = keywords.filter(k => k.isPsalm);

                                return (
                                    <>
                                        {defaults.length > 0 && (
                                            <div className="flex flex-row items-center justify-center gap-1.5 flex-wrap">
                                                {defaults.map((keyword, i) => (
                                                    <span key={`def-${i}`} className={cn(`px-3 py-1 rounded-full ${fs.keyword} font-semibold transition-colors border shadow-sm w-fit max-w-full truncate bg-red-50/80 border-red-100 text-red-700 dark:bg-red-950/30 dark:border-red-900/50 dark:text-red-300`)}>
                                                        {keyword.text}
                                                    </span>
                                                ))}
                                            </div>
                                        )}
                                        {psalms.length > 0 && (
                                            <div className="flex flex-row items-center justify-center gap-1.5 flex-wrap">
                                                {psalms.map((keyword, i) => (
                                                    <span key={`ps-${i}`} className={cn(`px-3 py-1 rounded-full ${fs.keyword} font-semibold transition-colors border shadow-sm w-fit max-w-full truncate bg-blue-50 border-blue-100 text-blue-600 dark:bg-blue-950/30 dark:border-blue-800 dark:text-blue-300`)}>
                                                        {keyword.text}
                                                    </span>
                                                ))}
                                            </div>
                                        )}
                                    </>
                                );
                            })()}
                        </div>
                    )}

                    {/* Divider and Action Button Group */}
                    <div className="flex flex-col items-center w-full gap-3 mt-1">
                        <div className="w-12 h-[1px] bg-border/60" />
                        <AmenParticles trigger={showParticles} />

                        <button
                            onClick={handleToggle}
                            disabled={loading}
                            className={cn(
                                "group/btn relative flex items-center justify-center gap-2 px-8 py-3 rounded-full font-bold text-sm transition-all duration-500 active:scale-95 disabled:opacity-70",
                                isCompleted
                                    ? "bg-accent text-white shadow-lg shadow-accent/30"
                                    : "bg-primary text-primary-foreground shadow-md shadow-primary/20 hover:bg-primary/90"
                            )}
                        >
                            {loading ? (
                                <div className="h-4 w-4 border-2 border-white/50 border-t-white rounded-full animate-spin" />
                            ) : isCompleted ? (
                                <>
                                    <Check size={16} strokeWidth={3} />
                                    <span className="mr-2">아멘</span>
                                </>
                            ) : (
                                <span>읽음 표시</span>
                            )}
                        </button>
                    </div>

                    {/* Completion Message Removed */}

                    {isCompleted && (
                        <button
                            onClick={() => setShowJournal(true)}
                            className="mt-3 flex items-center gap-2 text-[11px] font-bold text-foreground/70 bg-muted/40 backdrop-blur-sm hover:bg-muted/60 transition-all py-2 px-5 rounded-xl border border-border/40 animate-in fade-in slide-in-from-bottom-2 duration-700 delay-300 hover:scale-[1.02] active:scale-[0.98]"
                        >
                            <PenLine size={12} className="text-primary/70" />
                            묵상 살펴보기
                        </button>
                    )}
                </div>
            </div>

            {/* Journaling Overlay */}
            {showJournal && (
                <div className="fixed inset-0 z-[100] flex flex-col bg-background animate-in slide-in-from-bottom-full duration-700 ease-[cubic-bezier(0.23,1,0.32,1)]">
                    <div className="flex items-center justify-between p-6 pt-12 border-b border-border/40">
                        <div className="flex items-center gap-2">
                            <PenLine size={18} className="text-primary" />
                            <h3 className="font-serif font-black text-lg">묵상일지</h3>
                        </div>
                        <button
                            onClick={() => setShowJournal(false)}
                            className="w-10 h-10 rounded-full bg-secondary flex items-center justify-center hover:bg-muted transition-colors"
                        >
                            <X size={20} />
                        </button>
                    </div>
                    <div className="flex-1 overflow-y-auto px-4 pb-4 pt-0 no-scrollbar">
                        <div className="max-w-2xl mx-auto">
                            <JournalView plan={plan} defaultView="history" />
                        </div>
                    </div>
                </div>
            )}

            {/* Reflection Challenge Modal */}
            {showReflection && (
                <ReflectionModal
                    planReferences={plan.verses}
                    onComplete={handleReflectionComplete}
                    onClose={() => setShowReflection(false)}
                />
            )}

            {/* Background Layer (Stacked Paper Effect) */}
            <div className="absolute inset-0 bg-card rounded-[1.5rem] border border-border/40 translate-y-2 scale-[0.96] -z-10 opacity-60 shadow-sm" />
            <div className="absolute inset-0 bg-card rounded-[1.5rem] border border-border/40 translate-y-4 scale-[0.92] -z-20 opacity-30 shadow-sm" />
        </div>
    );
}

"use client";

import { useState, useMemo, useEffect, useRef, useCallback } from "react";
import { BibleReadingPlan, UserProgress } from "@/types/bible";
import { User } from "@supabase/supabase-js";
import FullReadingView from "./FullReadingView";
import { calculateStreak } from "@/lib/stats";
import { useSearchParams } from "next/navigation";
import { getOfficialCategory, generateKeywords, calculateReadingTime } from "@/lib/bible-utils";
import { fetchYoutubePlaylist, getVideoForDay, parseDurationToMinutes } from "@/lib/youtube";
import HeaderIsland from "./layout/HeaderIsland";
import NavDock from "./layout/NavDock";
import SettingsView from "./SettingsView";
import { rescheduleFromSettings, registerNotificationTapListener } from "@/lib/notification-service";
import { Badge, Achievement } from "@/types/bible";
import { checkNewAchievements, loadAchievements, saveAchievements } from "@/lib/badge-service";
import { EncouragementBanner } from "./EncouragementBanner";
import BadgeOverlay from "./BadgeOverlay";
import BibleSearchModal from "./BibleSearchModal";


import { createClient } from "@/lib/supabase-client";
import { useBibleStore } from "@/store/useBibleStore";
import { cn } from "@/lib/utils";
import { App, URLOpenListenerEvent } from '@capacitor/app';

import { useDashboardNav, Tab } from "@/hooks/useDashboardNav";
import { useSharing } from "@/hooks/useSharing";
import HomeTab from "./dashboard-tabs/HomeTab";
import GroupTab from "./dashboard-tabs/GroupTab";
import RecordTab from "./dashboard-tabs/RecordTab";
import StatsTab from "./dashboard-tabs/StatsTab";
import AchievementTab from "./dashboard-tabs/AchievementTab";
import HymnsTab from "./dashboard-tabs/HymnsTab";
interface BibleDashboardProps {
    user: User | null;
    allPlans: BibleReadingPlan[];
    initialProgress: UserProgress[];
    appSettings: { key: string; value: string }[];
    initialDate: string;
    rawTargetPlan?: BibleReadingPlan;
}

export default function BibleDashboard({
    user,
    allPlans,
    initialDate,
    rawTargetPlan: initialRawTargetPlan
}: BibleDashboardProps) {
    const searchParams = useSearchParams();

    // Custom Hook for Navigation
    const { activeTab, setActiveTab, handleTouchStart, handleTouchEnd } = useDashboardNav();

    const [onlineCount, setOnlineCount] = useState(0);

    // State — persist selected date
    const [selectedDate, setSelectedDate] = useState(() => {
        if (typeof window !== 'undefined') {
            return localStorage.getItem('bible_last_date') || initialDate;
        }
        return initialDate;
    });
    const [videoDuration, setVideoDuration] = useState<number | null>(null);

    // Global Store
    const {
        completedPlanIds,
        toggleReading,
        logActivity,
        loadInitialData,
        isSyncing
    } = useBibleStore();

    // Settings from localStorage
    const [fontSize, setFontSize] = useState<'small' | 'medium' | 'large'>('medium');
    const [autoPlay, setAutoPlay] = useState(false);
    const [showEncouragement, setShowEncouragement] = useState(true);

    // Achievement State
    const [achievements, setAchievements] = useState<Achievement[]>([]);
    const [newBadge, setNewBadge] = useState<Badge | null>(null);

    // Full Reading Mode State
    const [showFullReading, setShowFullReading] = useState(false);
    const [showBibleSearch, setShowBibleSearch] = useState(false);
    const [directReference, setDirectReference] = useState<string | null>(null);

    // Streak display mode setting (item 1)
    const [streakDisplayMode, setStreakDisplayMode] = useState<'day' | 'progress'>('day');
    useEffect(() => {
        if (typeof window !== 'undefined') {
            const saved = localStorage.getItem('bible_streak_mode');
            if (saved === 'progress') setStreakDisplayMode('progress');

            const handleStreakModeChange = () => {
                const mode = localStorage.getItem('bible_streak_mode');
                setStreakDisplayMode(mode === 'progress' ? 'progress' : 'day');
            };
            window.addEventListener('bible_streak_mode_change', handleStreakModeChange);
            return () => window.removeEventListener('bible_streak_mode_change', handleStreakModeChange);
        }
    }, []);

    // Apply global font size
    useEffect(() => {
        const applyFontSize = () => {
            const size = localStorage.getItem('bible_font_size') || 'medium';
            setFontSize(size as 'small' | 'medium' | 'large');
            const scales: Record<string, string> = { small: '0.88', medium: '1', large: '1.15' };
            document.documentElement.style.setProperty('--font-scale', scales[size] || '1');
        };

        applyFontSize();
        setAutoPlay(localStorage.getItem('bible_autoplay') === 'true');
        setShowEncouragement(localStorage.getItem('bible_daily_verse') !== 'false');

        // Initialize Store
        loadInitialData(user?.id);

        if (user?.id) {
            // Trigger Sync (Local -> Cloud)
            useBibleStore.getState().syncWithSupabase(user.id);
        }

        // Listen for font-size changes from Settings tab
        if (typeof window !== 'undefined') {
            window.addEventListener('bible-font-change', applyFontSize);
        }

        // Load achievements
        setAchievements(loadAchievements());

        // Log 'Visit' activity (Level 1)
        const todayStr = new Date().toISOString().split('T')[0];
        logActivity(todayStr, 1);

        return () => {
            if (typeof window !== 'undefined') {
                window.removeEventListener('bible-font-change', applyFontSize);
            }
        };
    }, [user, loadInitialData, logActivity]);

    // Sync with URL
    useEffect(() => {
        const dateFromUrl = searchParams.get("date");
        if (dateFromUrl && dateFromUrl !== selectedDate) {
            setSelectedDate(dateFromUrl);
        }
    }, [searchParams, selectedDate]);

    // Fetch YouTube Video Duration
    useEffect(() => {
        async function fetchDuration() {
            try {
                // Calculate Day of Year
                const dateObj = new Date(selectedDate);
                const startYear = new Date(dateObj.getFullYear(), 0, 0);
                const diff = dateObj.getTime() - startYear.getTime();
                const oneDay = 1000 * 60 * 60 * 24;
                const dayOfYear = Math.floor(diff / oneDay);

                const videos = await fetchYoutubePlaylist();
                const videoData = getVideoForDay(videos, dayOfYear);
                if (videoData && videoData.duration) {
                    setVideoDuration(parseDurationToMinutes(videoData.duration));
                } else {
                    setVideoDuration(null);
                }
            } catch (error) {
                console.error("Failed to fetch video duration", error);
            }
        }
        fetchDuration();
    }, [selectedDate]);

    const handleDateChange = (newDateStr: string) => {
        setSelectedDate(newDateStr);
        // Item 2: Persist last working date
        if (typeof window !== 'undefined') {
            localStorage.setItem('bible_last_date', newDateStr);
        }
        const url = new URL(window.location.href);
        url.searchParams.set("date", newDateStr);
        window.history.pushState({}, "", url.toString());
    };

    // Derived State from Store
    const { streak, completedVerses, completedIds, progressPercent, daysLeft } = useMemo(() => {
        const currentCompletedIds = completedPlanIds;

        const completedDates = allPlans
            .filter(p => currentCompletedIds.includes(p.id))
            .map(p => p.date)
            .filter((d): d is string => !!d);

        const streak = calculateStreak(completedDates);

        const completedVerses = allPlans
            .filter(p => currentCompletedIds.includes(p.id))
            .reduce((acc: string[], p) => {
                if (p.verses) acc.push(...p.verses);
                return acc;
            }, []);

        const progressPercent = Math.round((currentCompletedIds.length / 365) * 100);
        const daysLeft = 365 - currentCompletedIds.filter(id => id > 0).length;

        return { streak, completedVerses, completedIds: currentCompletedIds, progressPercent, daysLeft };
    }, [completedPlanIds, allPlans]);

    // Target Plan Logic
    const targetPlan = useMemo(() => {
        let plan = initialRawTargetPlan;

        if (selectedDate !== initialDate || !plan) {
            const exact = allPlans.find(p => p.date === selectedDate);
            const targetMMDD = selectedDate.slice(5);
            plan = exact || allPlans.find(p => p.date && p.date.endsWith(targetMMDD));
        }

        if (!plan) return null;

        // Simplified Psalm 119 Logic
        const processedPlan = { ...plan };
        const day = processedPlan.day_of_year;
        const p119Mapping: Record<number, string> = {
            119: "시편 119편 1~32절", 274: "시편 119편 1~32절",
            120: "시편 119편 33-64절", 275: "시편 119편 33-64절",
            121: "시편 119편 65-96절", 276: "시편 119편 65-96절",
            122: "시편 119편 97-128절", 277: "시편 119편 97-128절",
            123: "시편 119편 129-152절", 278: "시편 119편 129-152절",
            124: "시편 119편 153-176절", 279: "시편 119편 153-176절"
        };
        const p119Text = p119Mapping[day];
        if (p119Text && !processedPlan.title.includes("시편 119절")) {
            processedPlan.title = `${processedPlan.title}, ${p119Text}`;
            if (!processedPlan.verses.includes(p119Text)) {
                processedPlan.verses = [...processedPlan.verses, p119Text];
            }
        }

        return {
            ...processedPlan,
            category: processedPlan.category || getOfficialCategory(processedPlan.verses),
            summary: processedPlan.summary || generateKeywords(processedPlan.verses),
            reading_time: processedPlan.reading_time || calculateReadingTime(processedPlan.verses)
        };
    }, [allPlans, selectedDate, initialDate, initialRawTargetPlan]);

    // Presence Logic
    useEffect(() => {
        const supabase = createClient();
        const start = Date.now();
        const channel = supabase.channel('global_reading_room', {
            config: { presence: { key: user?.id || `guest-${Math.random().toString(36).slice(2)}` } }
        });

        channel
            .on('presence', { event: 'sync' }, () => {
                const state = channel.presenceState();
                setOnlineCount(Object.keys(state).length);
            })
            .subscribe(async (status: string) => {
                if (status === 'SUBSCRIBED') {
                    await channel.track({
                        online_at: new Date().toISOString(),
                        is_member: !!user,
                        plan_id: targetPlan?.id
                    });
                }
            });

        return () => {
            supabase.removeChannel(channel);
        };
    }, [user, targetPlan?.id]);

    // Broadcast Activity
    const broadcastActivity = useCallback((type: 'start' | 'complete') => {
        const groupId = localStorage.getItem('bible_group_id');
        if (!groupId || !user) return;

        const supabase = createClient();
        supabase.channel(`group-${groupId}`).send({
            type: 'broadcast',
            event: 'activity',
            payload: {
                memberName: user.email?.split('@')[0] || '익명',
                type
            }
        });
    }, [user]);

    const isCompleted = targetPlan ? completedIds.includes(targetPlan.id) : false;

    const handleToggle = async (planId: number) => {
        const isNowCompleted = !isCompleted;

        // 1. Dispatch Action
        await toggleReading(planId, user?.id);

        // 2. Broadcast
        if (isNowCompleted) {
            broadcastActivity('complete');
        }

        // 3. Achievement Check
        if (isNowCompleted) {
            const newProgress = [...completedPlanIds, planId].map(id => ({
                plan_id: id,
                reading_plan: allPlans.find(p => p.id === id)
            })).filter(p => p.reading_plan);

            const newEarned = checkNewAchievements(newProgress as UserProgress[], achievements);
            if (newEarned.length > 0) {
                setNewBadge(newEarned[0]);
                const updatedAchievements = [
                    ...achievements,
                    ...newEarned.map(b => ({ badge_id: b.id, earned_at: new Date().toISOString() }))
                ];
                setAchievements(updatedAchievements);
                saveAchievements(updatedAchievements);
            }
        }
    };

    // State Refs for Notification Listener
    const streakRef = useRef(streak);
    const progressRef = useRef(0);

    const progress = useMemo(() => {
        if (!allPlans.length) return 0;
        return Math.round((completedPlanIds.length / allPlans.length) * 100);
    }, [allPlans.length, completedPlanIds.length]);

    useEffect(() => {
        streakRef.current = streak;
        progressRef.current = progress;
    }, [streak, progress]);

    // Custom Hook for Sharing
    const { handleShare } = useSharing({
        targetPlan,
        streak,
        progress: progressPercent,
        selectedDate
    });

    useEffect(() => {
        // Only update the daily notification content if we are viewing TODAY's plan
        // This prevents the daily notification from being overwritten with future/past content just by navigating.
        const todayStr = new Date().toISOString().split('T')[0];
        if (selectedDate === todayStr && targetPlan) {
            rescheduleFromSettings(
                targetPlan.title,
                targetPlan.verses?.[0]
            ).catch(console.warn);
        }

        // Register listener with cleanup
        let cleanup: (() => void) | undefined;

        const initListener = async () => {
            cleanup = await registerNotificationTapListener((action) => {
                const extra = action.notification.extra;
                if (extra?.type === "share_reminder") {
                    setActiveTab("home");
                    setTimeout(() => handleShare(), 500);
                } else {
                    setActiveTab("home");
                }
            });
        };

        initListener();

        return () => {
            if (cleanup) cleanup();
        };
    }, [handleShare, targetPlan, setActiveTab, selectedDate]);

    // Update Widget dynamically when Dashboard loads or state changes
    useEffect(() => {
        if (!targetPlan) return;
        const syncWidget = async () => {
            try {
                // Determine title and verses text
                const isSelectedToday = selectedDate === new Date().toISOString().split('T')[0];
                const dayTitle = targetPlan.title || "성경 365";

                // e.g. "창세기 1장" or "마 1-3장"
                let versesText = "말씀을 묵상하며 하루를 시작하세요";
                if (targetPlan.verses && targetPlan.verses.length > 0) {
                    versesText = targetPlan.verses.join(', ');
                    if (versesText.length > 25) {
                        versesText = versesText.substring(0, 22) + '...';
                    }
                }

                // If completed today, update verses tag
                if (isCompleted) {
                    versesText = "✅ " + versesText + " (읽음)";
                }

                const widgetData = {
                    title: dayTitle,
                    verse: versesText,
                    progress: progressPercent,
                    streak: streak,
                    date: new Date(selectedDate).toLocaleDateString('ko-KR', { month: 'long', day: 'numeric' }),
                    teaserVerse: useBibleStore.getState().currentTeaser
                };

                // Only load bridge dynamically
                const { default: WidgetBridge } = await import('@/lib/widget-bridge');
                await WidgetBridge.updateWidgetData(widgetData as any);
            } catch (err) {
                console.log("Widget sync skipped (non-native or error):", err);
            }
        };
        syncWidget();
    }, [targetPlan, isCompleted, progressPercent, streak, selectedDate]);

    // Handle AppUrlOpen (for Widget Youtube Clicks and General routing)
    useEffect(() => {
        let listener: any = null;
        const setupDeepLink = async () => {
            listener = await App.addListener('appUrlOpen', (event: URLOpenListenerEvent) => {
                const urlObj = new URL(event.url);
                // The widget passes 'targetAction' via Extra which translates to URL query param or scheme parsing depends on Android config 
                // Alternatively, if it's sent as an intent extra, we should check for custom actions in the capacitor bridge. 
                // Assuming traditional scheme or web URL:

                // For direct intents launched with putExtra like ytIntent.putExtra("targetAction", "youtube")
                // We'd typically read it if Capacitor parses extras into the URL or handle it natively and pass.
                // However, another simpler way is checking if 'targetAction=youtube' is in the URL.
                if (event.url.includes("youtube")) {
                    setAutoPlay(true);
                    setActiveTab("home");
                }
            });
        };

        setupDeepLink();

        return () => {
            if (listener) {
                listener.remove();
            }
        };
    }, [setActiveTab]);

    return (
        <div className="min-h-screen bg-background">
            <HeaderIsland
                title="성경 365"
                onLogoClick={() => setActiveTab("home")}
                onlineCount={onlineCount}
                isSyncing={isSyncing}
                hidden={activeTab === "group"}
            />

            <main
                className={cn(
                    "container flex-grow mx-auto max-w-2xl",
                    activeTab === "group" ? "hidden" : "",
                    activeTab !== "group" ? "px-4 pb-24" : "",
                    activeTab === "home" ? "pt-6" : activeTab !== "group" ? "pt-14" : ""
                )}
                onTouchStart={activeTab !== "group" ? handleTouchStart : undefined}
                onTouchEnd={activeTab !== "group" ? handleTouchEnd : undefined}
            >
                {activeTab === "home" && (
                    <HomeTab
                        selectedDate={selectedDate}
                        onDateChange={handleDateChange}
                        onShare={() => handleShare()}
                        onTextClick={() => setShowFullReading(true)}
                        targetPlan={targetPlan}
                        isCompleted={isCompleted}
                        onTogglePlan={handleToggle}
                        videoDuration={videoDuration}
                        fontSize={fontSize}
                        streak={streak}
                        progressPercent={progressPercent}
                        daysLeft={daysLeft}
                        autoPlay={autoPlay}
                        showEncouragement={showEncouragement}
                        onTabChange={setActiveTab}
                        streakDisplayMode={streakDisplayMode}
                    />
                )}

                {activeTab === "streak" && (
                    <StatsTab
                        completedPlanIds={completedPlanIds}
                        allPlans={allPlans}
                        onBack={() => setActiveTab("home")}
                    />
                )}

                {activeTab === "record" && (
                    <RecordTab
                        completedVerses={completedVerses}
                        completedPlanIds={completedPlanIds}
                        allPlans={allPlans}
                        currentDate={selectedDate}
                        onChapterClick={(ref: string) => {
                            setDirectReference(ref);
                            setShowFullReading(true);
                        }}
                    />
                )}

                {activeTab === "achievement" && (
                    <AchievementTab
                        streak={streak}
                        totalRead={completedPlanIds.length}
                        progressPercent={progressPercent}
                        completedPlanIds={completedPlanIds}
                        allPlans={allPlans}
                    />
                )}

                {activeTab === "hymn" && (
                    <HymnsTab />
                )}

                {activeTab === "menu" && (
                    <SettingsView onTabChange={(t: any) => setActiveTab(t)} />
                )}
            </main>

            {activeTab === "group" && (
                <GroupTab user={user} streak={streak} progressPercent={progressPercent} onTabChange={(t: any) => setActiveTab(t)} />
            )}

            <NavDock activeTab={activeTab} onTabChange={(tab: Tab) => setActiveTab(tab)} onSearchOpen={() => setShowBibleSearch(true)} />

            {showFullReading && (targetPlan || directReference) && (
                <FullReadingView
                    plan={directReference ? { id: 0, date: '', title: '', verses: [directReference], category: '' } as any : targetPlan}
                    onClose={() => { setShowFullReading(false); setDirectReference(null); }}
                    onNext={!directReference ? () => {
                        const nextDate = new Date(new Date(selectedDate).setDate(new Date(selectedDate).getDate() + 1)).toISOString().split('T')[0];
                        setSelectedDate(nextDate);
                    } : undefined}
                    onPrev={!directReference ? () => {
                        const prevDate = new Date(new Date(selectedDate).setDate(new Date(selectedDate).getDate() - 1)).toISOString().split('T')[0];
                        setSelectedDate(prevDate);
                    } : undefined}
                />
            )}

            <BibleSearchModal
                isOpen={showBibleSearch}
                onClose={() => setShowBibleSearch(false)}
                onSelect={(ref) => {
                    setDirectReference(ref);
                    setShowFullReading(true);
                    setShowBibleSearch(false);
                }}
            />

            <BadgeOverlay badge={newBadge} onClose={() => setNewBadge(null)} />
        </div>
    );
}

"use client";

import { BIBLE_BOOKS, BibleBook } from "@/lib/bible-metadata";
import { Check } from "lucide-react";
import { useState, useMemo } from "react";
import { cn } from "@/lib/utils";
import { ScrollArea } from "@/components/ui/scroll-area";
import { SmartCard } from "@/components/ui/smart-card";

interface BibleProgressMapProps {
    completedVerses: string[];
    onChapterClick?: (reference: string) => void;
}

interface BibleBookWithProgress extends BibleBook {
    percent: number;
    isCompleted: boolean;
}

export default function BibleProgressMap({ completedVerses, onChapterClick }: BibleProgressMapProps) {
    const [selectedBook, setSelectedBook] = useState<BibleBookWithProgress | null>(null);
    const [activeTab, setActiveTab] = useState<'OT' | 'NT'>('OT');

    // 1. Process completed verses into a Set of "BookName ChapterNumber"
    // Handles ranges like "창세기 1-3장" -> "창세기 1", "창세기 2", "창세기 3"
    const completedChapterSet = useMemo(() => {
        const set = new Set<string>();
        completedVerses.forEach(v => {
            const parts = v.trim().split(' ');
            if (parts.length < 2) return;

            const bookName = parts[0];
            const chapterPart = parts[1].replace('장', ''); // "1-3" or "1"

            if (chapterPart.includes('-')) {
                const [start, end] = chapterPart.split('-').map(n => parseInt(n));
                if (!isNaN(start) && !isNaN(end)) {
                    for (let i = start; i <= end; i++) {
                        set.add(`${bookName} ${i}`);
                    }
                }
            } else {
                const chapter = parseInt(chapterPart);
                if (!isNaN(chapter)) {
                    set.add(`${bookName} ${chapter}`);
                }
            }
        });
        return set;
    }, [completedVerses]);

    // Calculate progress for each book based on the detailed Set
    const booksWithProgress = useMemo(() => {
        return BIBLE_BOOKS.map(book => {
            let completedCount = 0;
            for (let i = 1; i <= book.chapters; i++) {
                if (completedChapterSet.has(`${book.name} ${i}`)) {
                    completedCount++;
                }
            }
            const percent = (completedCount / book.chapters) * 100;
            return { ...book, percent, isCompleted: percent === 100 };
        });
    }, [completedChapterSet]);

    const currentBooks = useMemo(() => {
        return booksWithProgress.filter(b => b.category === activeTab);
    }, [booksWithProgress, activeTab]);

    return (
        <div className="flex flex-col h-full min-h-[400px]">
            {/* Tab Switcher */}
            <div className="flex p-1 mb-4 bg-muted/30 rounded-lg">
                <button
                    onClick={() => setActiveTab('OT')}
                    className={cn(
                        "flex-1 py-1.5 text-xs font-bold rounded-md transition-all duration-300",
                        activeTab === 'OT'
                            ? "bg-amber-500 text-white shadow-sm"
                            : "text-muted-foreground hover:text-foreground hover:bg-muted/50"
                    )}
                >
                    구약 (39권)
                </button>
                <button
                    onClick={() => setActiveTab('NT')}
                    className={cn(
                        "flex-1 py-1.5 text-xs font-bold rounded-md transition-all duration-300",
                        activeTab === 'NT'
                            ? "bg-blue-500 text-white shadow-sm"
                            : "text-muted-foreground hover:text-foreground hover:bg-muted/50"
                    )}
                >
                    신약 (27권)
                </button>
            </div>

            <ScrollArea className="flex-1 pr-4 -mr-4">
                <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-5 gap-3 pb-4">
                    {currentBooks.map((book) => (
                        <button
                            key={book.name}
                            onClick={() => setSelectedBook(book)}
                            className={cn(
                                "relative flex flex-col items-center justify-center p-3 rounded-xl border transition-all duration-200 group",
                                book.isCompleted
                                    ? activeTab === 'OT'
                                        ? "bg-amber-500/5 border-amber-500/20 hover:bg-amber-500/10"
                                        : "bg-blue-500/5 border-blue-500/20 hover:bg-blue-500/10"
                                    : "bg-card hover:bg-muted border-border/40 hover:border-primary/30"
                            )}
                        >
                            {/* Progress Circle / Status */}
                            <div className="relative mb-2">
                                <div className={cn(
                                    "w-8 h-8 rounded-full flex items-center justify-center text-[10px] font-bold transition-colors",
                                    book.isCompleted
                                        ? activeTab === 'OT'
                                            ? "bg-amber-500 text-white"
                                            : "bg-blue-500 text-white"
                                        : book.percent > 0
                                            ? activeTab === 'OT'
                                                ? "bg-amber-500/10 text-amber-600"
                                                : "bg-blue-500/10 text-blue-600"
                                            : "bg-muted text-muted-foreground"
                                )}>
                                    {book.isCompleted ? (
                                        <Check size={14} strokeWidth={3} />
                                    ) : (
                                        <span>{Math.round(book.percent)}%</span>
                                    )}
                                </div>

                                {/* Active Indicator Ring */}
                                {book.percent > 0 && !book.isCompleted && (
                                    <div className="absolute inset-0 rounded-full border-2 border-primary/30 animate-pulse" />
                                )}
                            </div>

                            {/* Book Name */}
                            <span className={cn(
                                "text-xs font-serif font-semibold text-center leading-tight transition-colors font-scalable",
                                book.isCompleted ? "text-primary font-bold" : "text-muted-foreground group-hover:text-foreground"
                            )}>
                                {book.name}
                            </span>
                        </button>
                    ))}
                </div>
            </ScrollArea>

            {/* Chapter Detail Modal (Overlay) */}
            {selectedBook && (
                <div
                    className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-background/80 backdrop-blur-sm animate-in fade-in duration-200"
                    onClick={(e) => {
                        if (e.target === e.currentTarget) setSelectedBook(null);
                    }}
                >
                    <div className="w-full max-w-sm bg-card border border-border/50 rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[80vh]">
                        <div className="text-center p-4 border-b bg-muted/20 shrink-0">
                            <h3 className="text-xl font-serif font-bold text-foreground">{selectedBook.name}</h3>
                            <p className="text-xs text-muted-foreground uppercase tracking-widest mt-1">
                                {Math.round(selectedBook.percent)}% 완료 ({selectedBook.chapters}장 중)
                            </p>
                        </div>

                        {/* Native Scroll Container for reliability */}
                        <div className="flex-1 overflow-y-auto p-4 min-h-0 overscroll-contain">
                            <div className="grid grid-cols-5 gap-2 pb-2">
                                {Array.from({ length: selectedBook.chapters }, (_, i) => i + 1).map(chapter => {
                                    const isRead = completedChapterSet.has(`${selectedBook.name} ${chapter}`);
                                    const label = selectedBook.name === '시편' ? '편' : '장';
                                    return (
                                        <button
                                            key={chapter}
                                            onClick={() => onChapterClick?.(`${selectedBook.name} ${chapter}${label}`)}
                                            className={cn(
                                                "aspect-square rounded-md flex items-center justify-center text-xs font-medium border transition-colors active:scale-95",
                                                isRead
                                                    ? "bg-primary text-primary-foreground border-primary hover:bg-primary/80"
                                                    : "bg-muted/30 text-muted-foreground border-transparent hover:bg-muted hover:text-foreground"
                                            )}
                                        >
                                            {chapter}
                                        </button>
                                    );
                                })}
                            </div>
                        </div>

                        <div className="p-4 border-t bg-muted/20 shrink-0">
                            <button
                                onClick={() => setSelectedBook(null)}
                                className="w-full py-3 bg-secondary hover:bg-muted rounded-xl text-xs font-bold uppercase tracking-widest transition-colors"
                            >
                                닫기
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

