"use client";

import React, { useState, useEffect, useRef, useMemo } from "react";
import { X, ChevronLeft, ChevronRight, Type, Check, Moon, Sun, Monitor, AlignLeft, AlignJustify, Minus, Plus, Search, BookOpen, Sparkles } from "lucide-react";
import { BibleReadingPlan } from "@/types/bible";
import { cn } from "@/lib/utils";
import { BibleService, BibleVerse, BIBLE_BOOKS, BIBLE_ABBR_MAP } from "@/lib/bible-service";
import { useBibleSettings } from "@/hooks/useBibleSettings";
import { LivingTypography } from "@/lib/bible-typography";
import { BIBLE_BOOKS as METADATA_BOOKS } from "@/lib/bible-metadata";

interface FullReadingViewProps {
    plan?: BibleReadingPlan;
    onClose: () => void;
    onNext?: () => void;
    onPrev?: () => void;
}

type BibleVersion = 'KRV' | 'RNKSV' | 'NIV' | 'NLT';
type ViewMode = 'inline' | 'split' | 'none';

const VERSIONS: { id: BibleVersion, label: string }[] = [
    { id: 'KRV', label: '개역개정' },
    { id: 'RNKSV', label: '새번역' },
    { id: 'NIV', label: 'NIV' },
    { id: 'NLT', label: 'NLT' },
];

export default function FullReadingView({ plan, onClose, onNext, onPrev }: FullReadingViewProps) {
    // ---- State & Hooks ----
    const { settings, updateSettings, isLoaded } = useBibleSettings();
    const [version, setVersion] = useState<BibleVersion>('KRV');
    const [compareVersion, setCompareVersion] = useState<BibleVersion>('NIV');
    const [compareMode, setCompareMode] = useState<ViewMode>('none');

    // UI Visibility States
    const [showControls, setShowControls] = useState(true);
    const [showNavModal, setShowNavModal] = useState(false);

    const [showTypographyPanel, setShowTypographyPanel] = useState(false);
    const [showVersionSelector, setShowVersionSelector] = useState(false);

    // Data States
    const [currentReferences, setCurrentReferences] = useState<string[]>(plan?.verses || ["창세기 1장"]);
    const [textData, setTextData] = useState<BibleVerse[]>([]);
    const [contrastData, setContrastData] = useState<BibleVerse[]>([]);
    const [isLoading, setIsLoading] = useState(false);

    // Nav Modal States
    const [selectedBookIndex, setSelectedBookIndex] = useState(0);
    const [searchQuery, setSearchQuery] = useState('');
    const [isManualMode, setIsManualMode] = useState(false);

    // Extract current book name for dynamic category
    const currentBookMatch = currentReferences?.[0]?.match(/^([가-힣0-9a-zA-Z\s]+?)\s*\d+/);
    const currentBookName = currentBookMatch ? currentBookMatch[1].trim() : '';
    const dynamicCategory = METADATA_BOOKS.find(b => b.name === currentBookName)?.subCategory;
    const categoryToShow = isManualMode ? dynamicCategory : (plan?.category || dynamicCategory);

    const contentRef = useRef<HTMLDivElement>(null);
    const lastScrollY = useRef(0);

    // Dynamic Title based on current text
    const displayTitle = useMemo(() => {
        if (!textData.length) return "로딩 중...";

        const chaptersMap = new Map<string, Set<number>>();

        for (const v of textData) {
            if (!chaptersMap.has(v.book)) {
                chaptersMap.set(v.book, new Set<number>());
            }
            chaptersMap.get(v.book)!.add(v.chapter);
        }

        const parts: string[] = [];

        for (const [book, chaptersSet] of Array.from(chaptersMap.entries())) {
            const abbr = BIBLE_ABBR_MAP[book] || book.substring(0, 1);
            const chapters = Array.from(chaptersSet).sort((a, b) => a - b);

            const ranges: string[] = [];
            let rangeStart = chapters[0];
            let prev = chapters[0];

            for (let i = 1; i < chapters.length; i++) {
                if (chapters[i] === prev + 1) {
                    prev = chapters[i];
                } else {
                    ranges.push(rangeStart === prev ? `${rangeStart}` : `${rangeStart}-${prev}`);
                    rangeStart = chapters[i];
                    prev = chapters[i];
                }
            }
            ranges.push(rangeStart === prev ? `${rangeStart}` : `${rangeStart}-${prev}`);

            parts.push(`${abbr} ${ranges.join(', ')}`);
        }

        return parts.join(', ');
    }, [textData]);

    // ---- Effects ----

    // Sync initial Plan reference
    useEffect(() => {
        if (plan && plan.verses.length > 0) {
            setCurrentReferences(plan.verses);
        }
    }, [plan]);

    // Load API Data
    useEffect(() => {
        const load = async () => {
            setIsLoading(true);
            try {
                const allVerses: BibleVerse[] = [];
                const allContrastVerses: BibleVerse[] = [];

                for (const reference of currentReferences) {
                    const mainText = await BibleService.getChapterContent(reference, version);
                    allVerses.push(...mainText.verses);

                    if (compareMode !== 'none') {
                        const subText = await BibleService.getChapterContent(reference, compareVersion);
                        allContrastVerses.push(...subText.verses);
                    }
                }

                setTextData(allVerses);
                setContrastData(allContrastVerses);

                // Pre-fetch adjacent if it's a single chapter
                if (currentReferences.length === 1 && allVerses.length > 0) {
                    const book = allVerses[0].book;
                    const chapter = allVerses[0].chapter;
                    BibleService.prefetchAdjacent(book, chapter, version);
                }

                // Scroll reset
                if (contentRef.current) {
                    contentRef.current.scrollTo({ top: 0, behavior: 'smooth' });
                }
            } catch (err) {
                console.error("Failed to load bible verses:", err);
            } finally {
                setIsLoading(false);
            }
        };
        load();
    }, [currentReferences, version, compareMode, compareVersion]);

    // Zero-Distraction Scroll Logic
    useEffect(() => {
        const handleScroll = () => {
            if (!contentRef.current) return;
            const currentScrollY = contentRef.current.scrollTop;

            // Hide on scroll down, show on scroll up (or near top)
            if (currentScrollY > lastScrollY.current && currentScrollY > 100) {
                if (!showTypographyPanel && !showNavModal && !showVersionSelector) {
                    setShowControls(false);
                }
            } else if (currentScrollY < lastScrollY.current - 10 || currentScrollY <= 100) {
                setShowControls(true);
            }
            lastScrollY.current = currentScrollY;
        };
        const element = contentRef.current;
        element?.addEventListener('scroll', handleScroll, { passive: true });
        return () => element?.removeEventListener('scroll', handleScroll);
    }, [showTypographyPanel, showNavModal, showVersionSelector]);

    // Auto Theme Logic based on settings
    useEffect(() => {
        if (!isLoaded) return;
        const root = window.document.documentElement;
        if (settings.theme === 'system') {
            const systemTheme = window.matchMedia("(prefers-color-scheme: dark)").matches ? "dark" : "light";
            root.classList.remove("light", "dark", "sepia");
            root.classList.add(systemTheme);
        } else {
            root.classList.remove("light", "dark", "sepia");
            root.classList.add(settings.theme);
        }
    }, [settings.theme, isLoaded]);

    const navigateToChapter = (bookName: string, chapter: number) => {
        const label = bookName === '시편' ? '편' : '장';
        setCurrentReferences([`${bookName} ${chapter}${label}`]);
        setIsManualMode(true);
        setShowNavModal(false);
    };

    const bookFiltered = useMemo(() => {
        if (!searchQuery) return BIBLE_BOOKS;
        return BIBLE_BOOKS.filter(b => b.name.includes(searchQuery));
    }, [searchQuery]);

    if (!isLoaded) return null;

    return (
        <div className="fixed inset-0 z-[100] bg-background text-foreground flex flex-col font-sans transition-colors duration-500 animate-in slide-in-from-bottom-4">

            {/* ---- 1. Header Sticky Nav (Smart Navigation) ---- */}
            <div className={cn(
                "absolute top-0 left-0 right-0 z-30 flex flex-col pt-10 pb-4 px-4 bg-background/90 backdrop-blur-xl border-b border-border/30 transition-all duration-500 ease-in-out",
                showControls ? "translate-y-0 opacity-100" : "-translate-y-full opacity-0 pointer-events-none"
            )}>
                <div className="flex items-center justify-between">
                    {/* Close Area */}
                    <button onClick={onClose} className="p-2 -ml-2 rounded-full hover:bg-muted/80 transition-colors">
                        <X size={24} className="text-muted-foreground" />
                    </button>

                    <button
                        onClick={() => setShowNavModal(true)}
                        className="flex flex-col items-center px-4 py-1.5 hover:bg-muted/50 rounded-2xl transition-colors"
                    >
                        {categoryToShow && (
                            <span className="text-[10px] uppercase font-bold tracking-widest text-muted-foreground mb-0.5">
                                {categoryToShow}
                            </span>
                        )}
                        <div className="flex items-center gap-1.5">
                            <h2 className="text-lg font-serif font-bold whitespace-nowrap">{displayTitle}</h2>
                            <span className="w-1.5 h-1.5 rounded-full bg-primary/80" />
                        </div>
                    </button>

                    {/* Right Tools (Version & Typo) */}
                    <div className="flex items-center gap-1 relative">
                        {/* Typography */}
                        <button
                            onClick={() => setShowTypographyPanel(!showTypographyPanel)}
                            className={cn(
                                "p-2 rounded-full transition-colors",
                                showTypographyPanel ? "bg-primary/10 text-primary" : "text-muted-foreground hover:bg-muted/80"
                            )}
                        >
                            <Type size={20} />
                        </button>
                    </div>
                </div>

                {/* Sub-Header: Version & Compare Selectors */}
                <div className="flex justify-between items-center mt-4">
                    <div className="relative">
                        <button
                            onClick={() => setShowVersionSelector(!showVersionSelector)}
                            className="flex items-center gap-2 px-3 py-1.5 bg-muted/40 hover:bg-muted/80 rounded-full text-xs font-bold transition-colors"
                        >
                            {VERSIONS.find(v => v.id === version)?.label}
                            <span className="text-[10px] border-l border-border/50 pl-2">변경</span>
                        </button>

                        {/* Version Dropdown */}
                        {showVersionSelector && (
                            <>
                                <div className="fixed inset-0 z-40" onClick={() => setShowVersionSelector(false)} />
                                <div className="absolute top-full left-0 mt-2 w-36 bg-popover rounded-xl border shadow-xl overflow-hidden z-50 animate-in fade-in slide-in-from-top-2 duration-200">
                                    {VERSIONS.map(v => (
                                        <button
                                            key={v.id}
                                            onClick={() => { setVersion(v.id); setShowVersionSelector(false); }}
                                            className="w-full flex items-center justify-between px-3 py-2.5 hover:bg-muted/50 text-xs font-semibold"
                                        >
                                            {v.label}
                                            {version === v.id && <Check size={14} className="text-primary" />}
                                        </button>
                                    ))}
                                </div>
                            </>
                        )}
                    </div>

                    <div className="flex bg-muted/30 rounded-full p-1 border">
                        <button
                            onClick={() => updateSettings({ livingTypography: true })}
                            className={cn("px-3 py-1 text-[10px] font-bold rounded-full transition-all", settings.livingTypography ? "bg-background shadow-sm text-primary" : "text-muted-foreground hover:bg-muted/50")}
                        >
                            감성읽기 on
                        </button>
                        <button
                            onClick={() => updateSettings({ livingTypography: false })}
                            className={cn("px-3 py-1 text-[10px] font-bold rounded-full transition-all", !settings.livingTypography ? "bg-background shadow-sm text-foreground" : "text-muted-foreground hover:bg-muted/50")}
                        >
                            감성읽기 off
                        </button>
                    </div>
                </div>
            </div>

            {/* ---- 2. Main Reading Canvas (Zero-Distraction) ---- */}
            <div
                ref={contentRef}
                className={cn(
                    "flex-1 overflow-y-auto w-full flex flex-col pt-[8.5rem] pb-32 transition-colors duration-500",
                    settings.theme === 'sepia' ? 'bg-[#f4ecd8] text-[#433422]' : 'bg-background text-foreground'
                )}
            >
                {isLoading ? (
                    <div className="max-w-3xl mx-auto w-full px-6 space-y-6 pt-10">
                        {[...Array(8)].map((_, i) => (
                            <div key={i} className="h-4 bg-muted/40 rounded w-full animate-pulse" style={{ width: `${Math.random() * 40 + 60}%` }} />
                        ))}
                    </div>
                ) : (
                    <div className="max-w-3xl mx-auto w-full px-6 md:px-12">
                        {textData.map((v, i) => {
                            const isTitleRow = i === 0 || textData[i - 1].chapter !== v.chapter || textData[i - 1].book !== v.book;

                            return (
                                <React.Fragment key={`${v.book}-${v.chapter}-${v.verse}`}>
                                    {isTitleRow && (
                                        <div className="text-center pt-8 pb-6">
                                            <h3 className="text-3xl md:text-4xl font-bold font-serif tracking-tight text-primary">
                                                {v.book} {v.chapter}{v.book === '시편' ? '편' : '장'}
                                            </h3>
                                        </div>
                                    )}
                                    <div className="flex gap-3 md:gap-5 group mb-3 relative">
                                        {/* Verse Number Ribbon */}
                                        <span className={cn(
                                            "min-w-6 text-right text-xs md:text-sm font-sans font-bold pt-1.5 select-none transition-colors",
                                            compareMode !== 'none' ? "text-primary/70" : "text-muted-foreground/30 group-hover:text-primary"
                                        )}>
                                            {v.verse}
                                        </span>

                                        {/* Text Engine */}
                                        <div className="flex-1 space-y-1.5">
                                            {/* Primary Text */}
                                            {settings.livingTypography ? (
                                                <LivingTypography
                                                    text={v.text}
                                                    className={cn(
                                                        "leading-relaxed transition-all duration-300 antialiased block",
                                                        settings.fontFamily === 'serif' ? 'font-serif' : 'font-sans'
                                                    )}
                                                    style={{
                                                        fontSize: `${settings.fontSize}px`,
                                                        lineHeight: settings.lineHeight
                                                    }}
                                                />
                                            ) : (
                                                <p
                                                    className={cn(
                                                        "leading-relaxed transition-all duration-300 antialiased block",
                                                        settings.fontFamily === 'serif' ? 'font-serif' : 'font-sans'
                                                    )}
                                                    style={{
                                                        fontSize: `${settings.fontSize}px`,
                                                        lineHeight: settings.lineHeight
                                                    }}
                                                >
                                                    {v.text}
                                                </p>
                                            )}

                                            {/* Compare Inline Data */}
                                            {compareMode === 'inline' && contrastData[i] && (
                                                <p
                                                    className="font-sans text-blue-600/90 dark:text-blue-400 border-l-[3px] border-blue-500/30 pl-4 py-1.5 italic"
                                                    style={{
                                                        fontSize: `${settings.fontSize * 0.85}px`,
                                                        lineHeight: settings.lineHeight * 0.9
                                                    }}
                                                >
                                                    {contrastData[i].text}
                                                </p>
                                            )}
                                        </div>
                                    </div>
                                </React.Fragment>
                            );
                        })}

                        {/* EOF Spacer */}
                        <div className="h-20 w-full border-b border-border/20 mb-8 mt-12 flex justify-center items-end pb-2">
                            <div className="w-2 h-2 rounded-full bg-border" />
                        </div>
                    </div>
                )}
            </div>

            {/* ---- 3. Bottom Action Nav (Shown when controls are visible) ---- */}
            <div className={cn(
                "absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-background via-background/90 to-transparent flex justify-between items-end h-32 z-20 pointer-events-none transition-all duration-500 ease-in-out",
                showControls && !showTypographyPanel ? "translate-y-0 opacity-100" : "translate-y-full opacity-0"
            )}>
                {onPrev && (
                    <button onClick={onPrev} className="pointer-events-auto flex items-center gap-2 mb-2 px-6 py-3 rounded-full bg-background/80 shadow-lg border border-border/40 text-foreground hover:bg-muted font-bold text-sm transition-transform active:scale-95">
                        <ChevronLeft size={18} /> 이전
                    </button>
                )}
                {onNext && (
                    <button onClick={onNext} className="pointer-events-auto flex items-center gap-2 mb-2 px-6 py-3 rounded-full bg-primary text-primary-foreground shadow-lg font-bold text-sm transition-transform active:scale-95 ml-auto">
                        다음 <ChevronRight size={18} />
                    </button>
                )}
            </div>

            {/* ---- 4. Typography & Display Settings (Bottom Sheet) ---- */}
            {showTypographyPanel && (
                <>
                    <div className="fixed inset-0 bg-black/20 z-40 backdrop-blur-sm transition-opacity" onClick={() => setShowTypographyPanel(false)} />
                    <div className="absolute bottom-0 left-0 right-0 bg-background border-t shadow-2xl z-50 rounded-t-3xl pt-2 pb-10 px-6 animate-in slide-in-from-bottom duration-300">
                        <div className="w-12 h-1.5 bg-muted mx-auto rounded-full mb-6" />

                        <div className="space-y-8 max-w-sm mx-auto">
                            {/* Font Size */}
                            <div>
                                <h4 className="text-xs font-bold text-muted-foreground uppercase tracking-widest mb-3">글자 크기</h4>
                                <div className="flex items-center gap-4 p-1 bg-muted/40 rounded-2xl border">
                                    <button
                                        onClick={() => updateSettings({ fontSize: Math.max(12, settings.fontSize - 2) })}
                                        className="p-3 hover:bg-background rounded-xl text-muted-foreground transition-all flex-1 flex justify-center"
                                    >
                                        <Minus size={20} />
                                    </button>
                                    <span className="font-bold font-mono w-8 text-center">{settings.fontSize}</span>
                                    <button
                                        onClick={() => updateSettings({ fontSize: Math.min(36, settings.fontSize + 2) })}
                                        className="p-3 hover:bg-background rounded-xl text-foreground transition-all flex-1 flex justify-center"
                                    >
                                        <Plus size={20} />
                                    </button>
                                </div>
                            </div>

                            {/* Theme options */}
                            <div>
                                <h4 className="text-xs font-bold text-muted-foreground uppercase tracking-widest mb-3">테마</h4>
                                <div className="grid grid-cols-4 gap-2">
                                    {[
                                        { id: 'system', icon: Monitor, label: '시스템' },
                                        { id: 'light', icon: Sun, label: '화이트' },
                                        { id: 'dark', icon: Moon, label: '다크' },
                                        { id: 'sepia', icon: BookOpen, label: '세피아' },
                                    ].map(t => (
                                        <button
                                            key={t.id}
                                            onClick={() => updateSettings({ theme: t.id as any })}
                                            className={cn(
                                                "flex flex-col items-center gap-1.5 p-3 rounded-2xl border transition-all",
                                                settings.theme === t.id ? "bg-primary text-primary-foreground border-primary shadow-md" : "bg-card text-muted-foreground border-border/50 hover:bg-muted"
                                            )}
                                        >
                                            <t.icon size={18} />
                                            <span className="text-[10px] font-bold">{t.label}</span>
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Line Height & Font Family */}
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <h4 className="text-xs font-bold text-muted-foreground uppercase tracking-widest mb-3">글꼴</h4>
                                    <div className="flex bg-muted/40 p-1 rounded-2xl border">
                                        <button
                                            onClick={() => updateSettings({ fontFamily: 'serif' })}
                                            className={cn("flex-1 py-2 text-sm font-serif font-bold rounded-xl transition-all", settings.fontFamily === 'serif' ? "bg-background shadow text-foreground" : "text-muted-foreground")}
                                        >
                                            명조
                                        </button>
                                        <button
                                            onClick={() => updateSettings({ fontFamily: 'sans' })}
                                            className={cn("flex-1 py-2 text-sm font-sans font-bold rounded-xl transition-all", settings.fontFamily === 'sans' ? "bg-background shadow text-foreground" : "text-muted-foreground")}
                                        >
                                            고딕
                                        </button>
                                    </div>
                                </div>
                                <div>
                                    <h4 className="text-xs font-bold text-muted-foreground uppercase tracking-widest mb-3">행간</h4>
                                    <div className="flex bg-muted/40 p-1 rounded-2xl border items-center">
                                        <button
                                            onClick={() => updateSettings({ lineHeight: Math.max(1.4, settings.lineHeight - 0.2) })}
                                            className="p-2 hover:bg-background rounded-xl text-muted-foreground flex-1 flex justify-center"
                                        >
                                            <AlignJustify size={16} />
                                        </button>
                                        <span className="text-xs font-bold w-6 text-center">{settings.lineHeight.toFixed(1)}</span>
                                        <button
                                            onClick={() => updateSettings({ lineHeight: Math.min(3.0, settings.lineHeight + 0.2) })}
                                            className="p-2 hover:bg-background rounded-xl text-foreground flex-1 flex justify-center"
                                        >
                                            <AlignLeft size={16} />
                                        </button>
                                    </div>
                                </div>
                            </div>

                            {/* Living Typography Toggle */}
                            <div>
                                <h4 className="text-xs font-bold text-muted-foreground uppercase tracking-widest mb-3">하이라이트 모드 (Living Typography)</h4>
                                <div className="flex bg-muted/40 p-1 rounded-2xl border">
                                    <button
                                        onClick={() => updateSettings({ livingTypography: true })}
                                        className={cn("flex-1 py-2 text-xs font-bold rounded-xl transition-all", settings.livingTypography ? "bg-primary text-primary-foreground shadow" : "text-muted-foreground")}
                                    >
                                        켜기
                                    </button>
                                    <button
                                        onClick={() => updateSettings({ livingTypography: false })}
                                        className={cn("flex-1 py-2 text-xs font-bold rounded-xl transition-all", !settings.livingTypography ? "bg-background shadow text-foreground" : "text-muted-foreground")}
                                    >
                                        끄기
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                </>
            )}

            {/* ---- 5. Smart Navigator Modal (Full Screen Index) ---- */}
            {showNavModal && (
                <div className="fixed inset-0 bg-background z-[200] flex flex-col animate-in zoom-in-95 duration-200">
                    <div className="flex items-center justify-between p-4 pt-12 border-b border-border/40">
                        <h2 className="text-lg font-bold">성경 탐색</h2>
                        <button onClick={() => setShowNavModal(false)} className="p-2 rounded-full bg-muted">
                            <X size={20} />
                        </button>
                    </div>

                    <div className="p-4 bg-muted/20">
                        <div className="relative">
                            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                            <input
                                type="text"
                                placeholder="성경책 이름 검색 (예: 창세기, 마태)"
                                value={searchQuery}
                                onChange={e => setSearchQuery(e.target.value)}
                                className="w-full bg-background border border-border/50 rounded-xl pl-9 pr-4 py-2.5 text-sm font-bold focus:outline-none focus:ring-2 focus:ring-primary"
                            />
                        </div>
                    </div>

                    <div className="flex-1 flex overflow-hidden">
                        {/* Book List */}
                        <div className="w-1/3 border-r overflow-y-auto no-scrollbar pb-10 bg-muted/5">
                            {bookFiltered.map((book, idx) => {
                                const realIdx = BIBLE_BOOKS.findIndex(b => b.name === book.name);
                                return (
                                    <button
                                        key={book.name}
                                        onClick={() => setSelectedBookIndex(realIdx)}
                                        className={cn(
                                            "w-full text-left px-4 py-3.5 text-sm font-bold transition-all border-b border-border/30",
                                            selectedBookIndex === realIdx
                                                ? "bg-primary/10 text-primary border-r-2 border-r-primary"
                                                : "text-foreground hover:bg-muted/50"
                                        )}
                                    >
                                        {book.name}
                                    </button>
                                );
                            })}
                        </div>

                        {/* Chapter List */}
                        <div className="flex-1 overflow-y-auto p-4 pb-20 no-scrollbar bg-card">
                            <h3 className="text-base font-bold mb-4 font-serif text-primary sticky top-0 bg-card py-2 border-b">
                                {BIBLE_BOOKS[selectedBookIndex].name} 몇 장을 읽으시겠어요?
                            </h3>
                            <div className="grid grid-cols-4 sm:grid-cols-5 gap-3">
                                {Array.from({ length: BIBLE_BOOKS[selectedBookIndex].chapters }).map((_, i) => (
                                    <button
                                        key={i}
                                        onClick={() => navigateToChapter(BIBLE_BOOKS[selectedBookIndex].name, i + 1)}
                                        className="aspect-square flex flex-col items-center justify-center bg-muted/30 hover:bg-primary hover:text-primary-foreground border rounded-2xl transition-colors shadow-sm active:scale-95"
                                    >
                                        <span className="text-lg font-bold font-sans">{i + 1}</span>
                                    </button>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            )}

        </div>
    );
}

"use client";
/* eslint-disable react-hooks/set-state-in-effect */

import { useState, useEffect } from "react";
import { SmartCard } from "./ui/smart-card";
import { Users, UserPlus, Trophy, Flame, MessageCircle, Send, Zap } from "lucide-react";
import { cn } from "@/lib/utils";
import { createClient } from "@/lib/supabase-client";
import { User, RealtimeChannel } from "@supabase/supabase-js";

interface GroupMember {
    id: string;
    email: string;
    name: string;
    streak: number;
    progress: number;
    lastActive: string;
    isOnline: boolean;
}

interface Presence {
    name: string;
    online_at?: string;
    streak?: number;
    progress?: number;
    presence_ref?: string;
}

interface BroadcastPayload {
    memberName?: string;
    userName?: string;
    type?: string;
    text?: string;
    from?: string;
    to?: string;
    emoji?: string;
}

interface DBMessage {
    id: number;
    group_id: string;
    user_name: string;
    user_email: string;
    message: string;
    type: string; // 'chat', 'system', etc.
    created_at: string;
}

interface GroupChallengeViewProps {
    user: User | null;
    streak: number;
    progress: number;
}

export default function GroupChallengeView({ user, streak, progress }: GroupChallengeViewProps) {
    const [groupId, setGroupId] = useState<string | null>(null);
    const [inviteCode, setInviteCode] = useState("");
    const [members, setMembers] = useState<GroupMember[]>([]);
    const [messages, setMessages] = useState<{ user: string, text: string, type: string }[]>([]);
    const [presenceState, setPresenceState] = useState<Record<string, Presence[]>>({});
    const [isConnected, setIsConnected] = useState(false);
    const [newMessage, setNewMessage] = useState("");
    const [pokeNotification, setPokeNotification] = useState<{ from: string, emoji: string } | null>(null);
    const supabase = createClient();

    // Load group from local storage or DB
    useEffect(() => {
        const savedGroup = localStorage.getItem('bible_group_id');
        if (savedGroup) setGroupId(savedGroup);
    }, []);

    // Load messages from Supabase (Persistent)
    useEffect(() => {
        if (!groupId) return;

        const fetchMessages = async () => {
            const { data, error } = await supabase
                .from('group_messages')
                .select('*')
                .eq('group_id', groupId)
                .order('created_at', { ascending: false })
                .limit(50);

            if (error) {
                console.error("Error fetching messages:", error);
            } else if (data) {
                // Map DB format to UI format
                const formatted = (data as DBMessage[]).map((m) => ({
                    user: m.user_name,
                    text: m.message,
                    type: m.type
                }));
                setMessages(formatted);
            }
        };

        fetchMessages();

        // Subscribe to new messages
        const channel = supabase.channel(`group-chat-${groupId}`)
            .on('postgres_changes', {
                event: 'INSERT',
                schema: 'public',
                table: 'group_messages',
                filter: `group_id=eq.${groupId}`
            }, (payload: any) => {
                const newMsg = payload.new as DBMessage;
                setMessages(prev => [{
                    user: newMsg.user_name,
                    text: newMsg.message,
                    type: newMsg.type
                }, ...prev].slice(0, 50));
            })
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [groupId, supabase]);

    // Sync Members from Chat History and Presence (Updated to use DB messages)
    useEffect(() => {
        const uniqueUsers = new Set<string>();
        // 1. Get users from chat history
        messages.forEach(msg => {
            if (msg.user !== 'System') uniqueUsers.add(msg.user);
        });

        // 2. Get users from Presence State
        Object.values(presenceState).forEach((presences) => {
            if (Array.isArray(presences)) {
                presences.forEach((p) => {
                    if (p.name) uniqueUsers.add(p.name);
                });
            }
        });

        // 3. Current User
        if (user) {
            uniqueUsers.add(user.email?.split('@')[0] || '나');
        }

        const updatedMembers = Array.from(uniqueUsers).map(userName => {
            // Check if user is in presence state (Online)
            let isOnline = false;
            let lastActive = new Date().toISOString();

            // Check presence for online status
            const onlinePresence = Object.values(presenceState).flat().find((p) => p.name === userName);
            if (onlinePresence) {
                isOnline = true;
                lastActive = onlinePresence.online_at || new Date().toISOString();
            }

            const memberStreak = onlinePresence?.streak ?? (userName === (user?.email?.split('@')[0] || '나') ? streak : Math.floor(Math.random() * 20));
            const memberProgress = onlinePresence?.progress ?? (userName === (user?.email?.split('@')[0] || '나') ? progress : Math.floor(Math.random() * 100));

            return {
                id: userName,
                email: "",
                name: userName,
                streak: memberStreak,
                progress: memberProgress,
                lastActive: lastActive,
                isOnline: isOnline
            };
        });

        updatedMembers.sort((a, b) => {
            if (a.isOnline === b.isOnline) return a.name.localeCompare(b.name);
            return a.isOnline ? -1 : 1;
        });

        setMembers(updatedMembers);

    }, [messages, presenceState, user, streak, progress]);

    // Supabase Realtime Sync
    useEffect(() => {
        if (!groupId || !user) return;

        const channel = supabase.channel(`group-${groupId}`, {
            config: {
                presence: { key: user.id }
            }
        });

        channel
            .on('presence', { event: 'sync' }, () => {
                const state = channel.presenceState();
                setPresenceState(state as Record<string, Presence[]>);
            })
            .on('broadcast', { event: 'activity' }, (payload: { payload: BroadcastPayload }) => {
                // Note: Supabase broadcast payload structure might be wrapped or direct depending on version/client
                // Usually it's in payload.payload or just payload depending on how it's sent.
                // Let's assume standard payload for now.
                // Correct logic: .on receives the payload directly.
                const { memberName, type } = payload.payload || payload; // Handle potential wrapping
                // Actually typescript might complain if I access .payload on BroadcastPayload interface?
                // Let's cast to any for the payload reception to be safe or define exact wrapper
                const actualPayload = (payload as any).payload || payload;
                const { memberName: name, type: msgType } = actualPayload as BroadcastPayload;

                if (name && msgType) {
                    const msg = msgType === 'complete'
                        ? `${name}님이 오늘의 말씀을 완독했습니다! 🎉`
                        : `${name}님이 성경 읽기를 시작했습니다. 📖`;
                    setMessages(prev => [{ user: 'System', text: msg, type: 'system' }, ...prev].slice(0, 50));
                }
            })

            .on('broadcast', { event: 'poke' }, (payload: any) => {
                const actualPayload = (payload as any).payload || payload;
                const { from, to, emoji } = actualPayload as BroadcastPayload;
                const myName = user.email?.split('@')[0] || '나';
                // Only show notification if I am the target
                if (to === myName && from && emoji) {
                    setPokeNotification({ from, emoji });
                    setTimeout(() => setPokeNotification(null), 3000);
                }
            })
            .subscribe(async (status: string) => {
                if (status === 'SUBSCRIBED') {
                    setIsConnected(true);
                    await channel.track({
                        id: user.id,
                        name: user.email?.split('@')[0] || '익명',
                        online_at: new Date().toISOString(),
                        streak: streak,
                        progress: progress
                    });
                } else if (status === 'CLOSED' || status === 'CHANNEL_ERROR') {
                    setIsConnected(false);
                }
            });


        return () => {
            supabase.removeChannel(channel);
            setIsConnected(false);
        };
    }, [groupId, user, streak, progress, supabase]);

    const handleJoinGroup = () => {
        if (inviteCode.trim()) {
            setGroupId(inviteCode);
            localStorage.setItem('bible_group_id', inviteCode);
        }
    };

    const sendMessage = async () => {
        if (!newMessage.trim() || !groupId) return;

        const userName = user?.email?.split('@')[0] || '익명';
        const text = newMessage;

        // Insert into DB
        const { error } = await supabase.from('group_messages').insert({
            group_id: groupId,
            user_name: userName,
            user_email: user?.email,
            message: text,
            type: 'chat'
        });

        if (error) {
            console.error("Message send failed:", error);
            alert("메시지 전송 실패");
        } else {
            setNewMessage("");
        }
    };

    const handlePoke = (targetName: string) => {
        if (!groupId || !user) return;
        const myName = user.email?.split('@')[0] || '익명';

        supabase.channel(`group-${groupId}`).send({
            type: 'broadcast',
            event: 'poke',
            payload: { from: myName, to: targetName, emoji: "🙏" }
        });

        // Optional: Local feedback or toast could be added here
    };

    if (!groupId) {
        return (
            <div className="space-y-6 py-4 animate-in fade-in duration-700">
                <SmartCard variant="elevated" className="bg-gradient-to-br from-primary/10 to-accent/5 border-primary/20 p-8 text-center">
                    <div className="w-20 h-20 rounded-full bg-primary/20 flex items-center justify-center mx-auto mb-6">
                        <Users size={40} className="text-primary" />
                    </div>
                    <h2 className="text-2xl font-serif font-black mb-2">공동체와 함께 읽기</h2>
                    <p className="text-sm text-muted-foreground mb-8">가족, 교회 소그룹 멤버들과 함께 읽으며<br />서로 격려하고 진행률을 공유해보세요.</p>

                    <div className="space-y-3">
                        <input
                            type="text"
                            placeholder="초대 코드 입력 (예: MYCHURCH)"
                            value={inviteCode}
                            onChange={(e) => setInviteCode(e.target.value.toUpperCase())}
                            className="w-full bg-background border border-border rounded-2xl px-4 py-4 text-center font-bold tracking-widest outline-none focus:border-primary transition-all"
                        />
                        <button
                            onClick={handleJoinGroup}
                            className="w-full py-4 rounded-2xl bg-primary text-primary-foreground font-bold shadow-lg shadow-primary/20 active:scale-95 transition-all"
                        >
                            그룹 참여하기
                        </button>
                    </div>
                </SmartCard>

                <div className="flex items-center gap-4 py-2">
                    <div className="flex-1 h-px bg-border/50" />
                    <span className="text-[10px] uppercase tracking-widest font-bold text-muted-foreground/50">OR</span>
                    <div className="flex-1 h-px bg-border/50" />
                </div>

                <button className="w-full py-3 rounded-2xl border border-dashed border-border text-xs font-bold text-muted-foreground hover:bg-muted/30 transition-all flex items-center justify-center gap-2">
                    <UserPlus size={14} />
                    새로운 챌린지 그룹 만들기
                </button>
            </div>
        );
    }

    return (
        <div className="space-y-4 py-2 animate-in slide-in-from-bottom-4 duration-700">
            <div className="flex items-center justify-between px-1">
                <div className="flex items-center gap-2">
                    <div className="px-2 py-1 bg-primary/10 text-primary text-[10px] font-black rounded-lg uppercase tracking-tighter">Group Challenge</div>
                    <div className="flex flex-col">
                        <h2 className="text-lg font-black leading-none">{groupId}</h2>
                        <button
                            onClick={() => {
                                if (groupId) {
                                    const text = `[성경 365] 함께 읽기에 초대합니다! 📖\n\n초대 코드: ${groupId}\n\n앱에서 코드를 입력하고 참여해보세요.`;
                                    navigator.clipboard.writeText(text);
                                    alert("✅ 초대 메시지가 복사되었습니다!");
                                }
                            }}
                            className="text-[10px] text-muted-foreground hover:text-primary transition-colors text-left flex items-center gap-1"
                        >
                            <span>초대 코드 복사</span>
                            <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="14" height="14" x="8" y="8" rx="2" ry="2" /><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2" /></svg>
                        </button>
                    </div>
                </div>
                <div className="flex items-center gap-2">
                    <button
                        onClick={async () => {
                            // Import dynamically to avoid SSR issues if needed, or use global
                            // Using the share-service function
                            const { encryptInviteCode } = await import("@/lib/crypto");
                            const encryptedCode = encryptInviteCode(groupId);

                            import("@/lib/share-service").then(({ shareViaKakao }) => {
                                shareViaKakao(
                                    `[성경 365] 함께 읽기 초대장 💌\n\n초대 코드: ${groupId}\n\n우리 함께 말씀을 읽으며 서로 격려해요!`,
                                    `https://bible-365-app.vercel.app/invite?code=${encryptedCode}`
                                );
                            });
                        }}
                        className="p-2 bg-[#FEE500] text-[#3C1E1E] rounded-full hover:bg-[#FEE500]/80 transition-colors shadow-sm"
                        title="카카오톡 초대"
                    >
                        <MessageCircle size={14} className="fill-[#3C1E1E] stroke-none" />
                    </button>
                    <button
                        onClick={() => {
                            if (confirm("정말 그룹에서 나가시겠습니까?")) {
                                localStorage.removeItem('bible_group_id');
                                setGroupId(null);
                            }
                        }}
                        className="p-2 bg-muted text-muted-foreground rounded-full hover:bg-red-100 hover:text-red-500 transition-colors"
                        title="그룹 나가기"
                    >
                        <span className="text-xs font-bold">OUT</span>
                    </button>
                </div>
            </div>

            {/* Leaderboard Summary */}
            <SmartCard variant="default" className="p-4 bg-muted/20 border-border/30">
                <div className="flex items-center gap-4 overflow-x-auto no-scrollbar pb-2">
                    {members.length > 0 ? members.slice(0, 5).map((member, i) => (
                        <div key={i} className="flex-none flex flex-col items-center gap-2 min-w-[60px]">
                            <div className="relative">
                                <div className={cn(
                                    "w-12 h-12 rounded-full border-2 bg-background overflow-hidden flex items-center justify-center text-xs font-bold",
                                    member.name === (user?.email?.split('@')[0] || '나') ? "border-primary text-primary" : "border-muted-foreground/20"
                                )}>
                                    {member.name.substring(0, 2)}
                                </div>
                                {i === 0 && <Trophy className="absolute -top-2 -right-2 text-yellow-500 fill-yellow-500" size={16} />}
                                {member.isOnline && <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 rounded-full border-2 border-background" />}
                            </div>
                            <div className="text-center">
                                <p className="text-[10px] font-bold truncate w-14">{member.name}</p>
                                <div className="flex items-center gap-0.5 justify-center mb-1">
                                    <Flame size={8} className="text-orange-500" />
                                    <span className="text-[9px] font-bold">{member.streak}일</span>
                                </div>
                                {member.name !== (user?.email?.split('@')[0] || '나') && (
                                    <button
                                        onClick={() => handlePoke(member.name)}
                                        className="text-[8px] bg-primary/10 hover:bg-primary/20 text-primary px-1.5 py-0.5 rounded-full font-bold transition-colors"
                                    >
                                        응원하기
                                    </button>
                                )}
                            </div>
                        </div>
                    )) : (
                        <div className="w-full text-center py-4 text-xs text-muted-foreground">
                            아직 멤버가 없습니다. 친구를 초대해보세요!
                        </div>
                    )}
                    <div className="w-px h-10 bg-border/50" />
                    <div className="flex-1 flex flex-col items-center justify-center gap-1 opacity-50">
                        <Users size={16} className="text-muted-foreground" />
                        <span className="text-[8px] font-black uppercase tracking-tighter">More members</span>
                    </div>
                </div>
            </SmartCard>

            {/* Realtime Activity & Chat */}
            <SmartCard variant="elevated" className="bg-card flex flex-col min-h-[400px]">
                {/* Messages List */}
                <div className="flex-1 p-4 space-y-4 overflow-y-auto h-[320px] no-scrollbar">
                    {messages.length === 0 && (
                        <div className="flex flex-col items-center justify-center h-full text-center space-y-2 opacity-30 py-20">
                            <MessageCircle size={32} />
                            <p className="text-xs font-bold">첫 인사를 나누거나<br />오늘의 읽기를 완료하고 소식을 전해보세요!</p>
                        </div>
                    )}
                    {messages.map((msg, i) => (
                        <div key={i} className={cn(
                            "group animate-in slide-in-from-bottom-2 duration-300",
                            (msg.type === 'system' || msg.user === 'System') ? "flex justify-center" : "flex flex-col items-start"
                        )}>
                            {(msg.type === 'system' || msg.user === 'System') ? (
                                <span className="bg-primary/5 text-primary text-[9px] font-bold px-3 py-1 rounded-full border border-primary/10">
                                    {msg.text}
                                </span>
                            ) : (
                                <div className="max-w-[85%]">
                                    <span className="text-[9px] font-bold text-muted-foreground ml-1 mb-1 block uppercase tracking-tighter">{msg.user}</span>
                                    <div className="bg-muted px-4 py-2.5 rounded-2xl rounded-tl-none text-xs font-medium shadow-sm border border-border/30">
                                        {msg.text}
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>

                {/* Input Area */}
                <div className="p-3 border-t border-border/40 bg-muted/10">
                    <div className="flex items-center gap-2">
                        <input
                            type="text"
                            placeholder="메시지 입력..."
                            value={newMessage}
                            onChange={(e) => setNewMessage(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && sendMessage()}
                            className="flex-1 bg-background border border-border/50 rounded-xl px-4 py-2 text-xs font-medium outline-none focus:border-primary/50 transition-all"
                        />
                        <button
                            onClick={sendMessage}
                            disabled={!newMessage.trim()}
                            className="w-10 h-10 rounded-xl bg-primary text-primary-foreground flex items-center justify-center disabled:opacity-50 transition-all hover:scale-105 active:scale-95 shadow-md shadow-primary/10"
                        >
                            <Send size={16} />
                        </button>
                    </div>
                </div>
            </SmartCard>

            {/* Live Status */}
            <div className="flex items-center gap-2 px-2 text-[10px] text-muted-foreground font-bold italic">
                <Zap size={10} className={cn("transition-colors", isConnected ? "text-green-500 animate-pulse" : "text-muted-foreground")} />
                <span>{isConnected ? "실시간으로 다른 지체들과 연결되어 있습니다" : "연결 중입니다..."}</span>
            </div>

            {/* Poke Notification Overlay */}
            {pokeNotification && (
                <div className="fixed inset-0 pointer-events-none flex items-center justify-center z-50 animate-in zoom-in-50 fade-in duration-300">
                    <div className="bg-background/90 backdrop-blur-md border border-primary/20 shadow-2xl rounded-3xl p-6 text-center space-y-2 pointer-events-auto">
                        <div className="text-4xl animate-bounce">{pokeNotification.emoji}</div>
                        <div>
                            <p className="text-sm font-black text-primary">{pokeNotification.from}님의 응원!</p>
                            <p className="text-xs text-muted-foreground">함께 기도하고 있어요</p>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

