            )}

            {/* Rhema Feed Full Screen Overlay */}
            {showFeed && (
                <RhemaFeedView journals={journals} onClose={() => setShowFeed(false)} />
            )}
        </div>
    );
}

'use client';

import Script from 'next/script';
import { useEffect } from 'react';
import { loadShareSettings } from '@/lib/share-service';

declare global {
    interface Window {
        Kakao: any;
    }
}

export default function KakaoScript() {
    // Re-initialize if key changes (optional, usually done on page load)
    useEffect(() => {
        const initKakao = () => {
            const settings = loadShareSettings();
            // Priority: 1. Env Var, 2. Local Storage
            const jsKey = process.env.NEXT_PUBLIC_KAKAO_JS_KEY || settings.kakaoJsKey;

            if (window.Kakao && !window.Kakao.isInitialized() && jsKey) {
                try {
                    window.Kakao.init(jsKey);
                    console.log("Kakao SDK Initialized with key length:", jsKey.length);
                } catch (e) {
                    console.error("Failed to init Kakao SDK", e);
                }
            }
        };

        // Try init immediately if script already loaded
        if (window.Kakao) {
            initKakao();
        }

        // Also listen for settings changes if needed, but for now simple init is enough
        const handleFocus = () => initKakao();
        window.addEventListener('focus', handleFocus);
        return () => window.removeEventListener('focus', handleFocus);
    }, []);

    return (
        <Script
            src="https://t1.kakaocdn.net/kakao_js_sdk/2.7.4/kakao.min.js"
            integrity="sha384-DKYJZ8NLiK8AOplggwK6tOBa/+GqSaElLewisfLXaJclOH0/gIkeuzPZFmWk+52D"
            crossOrigin="anonymous"
            strategy="lazyOnload"
            onLoad={() => {
                const settings = loadShareSettings();
                const jsKey = process.env.NEXT_PUBLIC_KAKAO_JS_KEY || settings.kakaoJsKey;

                if (window.Kakao && !window.Kakao.isInitialized() && jsKey) {
                    try {
                        window.Kakao.init(jsKey);
                    } catch (e) {
                        console.error("Failed to init Kakao SDK", e);
                    }
                }
            }}
        />
    );
}

"use client";

import { forwardRef, useState } from "react";
import { Quote, Share2, Loader2, Download } from "lucide-react";
import { toBlob } from 'html-to-image';
import { Button } from "./ui/button";

interface LiturgyCardProps {
    date: string;
    content: string;
    theme?: 'dawn' | 'dusk' | 'midnight';
}

export const LiturgyCard = forwardRef<HTMLDivElement, LiturgyCardProps>(({ date, content, theme = 'dawn' }, ref) => {
    const [isSharing, setIsSharing] = useState(false);
    const gradients = {
        dawn: "from-orange-100 via-rose-100 to-amber-100 text-stone-800",
        dusk: "from-slate-800 via-purple-900 to-slate-900 text-white",
        midnight: "from-gray-900 via-slate-800 to-black text-gray-200"
    };

    const handleShare = async () => {
        setIsSharing(true);
        try {
            const node = document.getElementById('liturgy-card-content');
            if (!node) return;

            // Wait a bit for fonts to load/render if needed, but usually ok here.
            // toBlob can be heavy.
            const blob = await toBlob(node, { cacheBust: true });
            if (!blob) return;

            const file = new File([blob], 'prayer-card.png', { type: 'image/png' });

            if (navigator.share && navigator.canShare({ files: [file] })) {
                await navigator.share({
                    files: [file],
                    title: 'My Prayer',
                    text: content
                });
            } else {
                // Fallback: Download
                const link = document.createElement('a');
                link.download = 'prayer-card.png';
                link.href = URL.createObjectURL(blob);
                link.click();
            }
        } catch (error) {
            console.error('Sharing failed', error);
        } finally {
            setIsSharing(false);
        }
    };

    return (
        <div className="relative group max-w-sm mx-auto">
            <div
                id="liturgy-card-content"
                ref={ref}
                className={`relative p-8 rounded-3xl overflow-hidden bg-gradient-to-br ${gradients[theme]} shadow-xl`}
            >
                <div className="absolute top-4 left-4 opacity-20">
                    <Quote size={48} />
                </div>

                <div className="relative z-10 flex flex-col h-full items-center text-center space-y-6">
                    <div className="space-y-1">
                        <h3 className="text-xs font-bold tracking-[0.2em] uppercase opacity-70">
                            Today's Liturgy
                        </h3>
                        <p className="text-sm font-serif italic opacity-60">{date}</p>
                    </div>

                    <div className="flex-1 flex items-center justify-center">
                        <p className="text-lg leading-relaxed font-medium font-serif whitespace-pre-wrap">
                            {content}
                        </p>
                    </div>

                    <div className="w-8 h-1 bg-current opacity-20 rounded-full" />

                    <p className="text-[10px] tracking-widest opacity-50 uppercase">
                        Rhema AI Spiritual Twin
                    </p>
                </div>
            </div>

            <div className="absolute -bottom-12 left-0 right-0 flex justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                <Button
                    variant="secondary"
                    size="sm"
                    className="shadow-lg rounded-full gap-2"
                    onClick={handleShare}
                    disabled={isSharing}
                >
                    {isSharing ? <Loader2 size={14} className="animate-spin" /> : <Share2 size={14} />}
                    {isSharing ? 'Sharing...' : 'Share Card'}
                </Button>
            </div>
        </div>
    );
});

LiturgyCard.displayName = "LiturgyCard";

"use client";

import { useEffect, useState } from 'react';
import { Capacitor } from '@capacitor/core';

export function PushNotificationManager() {
    useEffect(() => {
        if (Capacitor.getPlatform() === 'web') return;

        const registerPush = async () => {
            try {
                // Dynamically import to avoid SSR issues
                const { PushNotifications } = await import('@capacitor/push-notifications');

                // Check permission — never block app launch
                let permStatus = await PushNotifications.checkPermissions();

                if (permStatus.receive === 'prompt') {
                    permStatus = await PushNotifications.requestPermissions();
                }

                if (permStatus.receive !== 'granted') {
                    // User denied — gracefully continue without push
                    console.warn('Push notification permission not granted — app continues normally');
                    return;
                }

                // Register safely
                try {
                    await PushNotifications.register();
                } catch (regErr) {
                    console.warn('Push registration failed (non-critical):', regErr);
                    return;
                }

                // Listeners
                PushNotifications.addListener('registration', (token) => {
                    console.log('Push Token:', token.value);
                });

                PushNotifications.addListener('registrationError', (error) => {
                    console.warn('Push Registration Error (non-critical):', error);
                });

                PushNotifications.addListener('pushNotificationReceived', (notification) => {
                    console.log('Push Received:', notification);
                });

                PushNotifications.addListener('pushNotificationActionPerformed', (notification) => {
                    console.log('Push Action:', notification);
                });

            } catch (e) {
                // Absolute catch-all: NEVER block app startup
                console.warn('Push notification setup failed gracefully:', e);
            }
        };

        registerPush();

        return () => {
            import('@capacitor/push-notifications').then(({ PushNotifications }) => {
                PushNotifications.removeAllListeners();
            }).catch(() => { });
        };
    }, []);

    return null;
}

"use client";

import { useMemo } from "react";
import {
    startOfYear,
    endOfYear,
    format,
    addDays,
    startOfWeek,
    endOfWeek,
    eachWeekOfInterval
} from "date-fns";
import { cn } from "@/lib/utils";
import { UserProgress, BibleReadingPlan } from "@/types/bible";
import { useBibleStore } from "@/store/useBibleStore";

interface ReadingHeatmapProps {
    progress: UserProgress[];
    allPlans: BibleReadingPlan[];
    currentDate: string;
}

export default function ReadingHeatmap({ progress, allPlans, currentDate }: ReadingHeatmapProps) {
    const yearStart = startOfYear(new Date(currentDate));
    const yearEnd = endOfYear(new Date(currentDate));

    // We want to show a grid of 53 weeks
    const weeks = useMemo(() => {
        const start = startOfWeek(yearStart, { weekStartsOn: 0 }); // Sunday
        const end = endOfWeek(yearEnd, { weekStartsOn: 0 });
        const allWeeks = eachWeekOfInterval({ start, end }, { weekStartsOn: 0 });

        return allWeeks.map(weekStart => {
            return Array.from({ length: 7 }).map((_, i) => {
                const day = addDays(weekStart, i);
                const dateStr = format(day, "yyyy-MM-dd");
                const plan = allPlans.find(p => p.date === dateStr);
                const isCompleted = plan && progress.some(prog => prog.plan_id === plan.id);
                const isThisYear = day.getFullYear() === yearStart.getFullYear();

                return {
                    date: day,
                    dateStr,
                    isCompleted,
                    isThisYear,
                    planTitle: plan?.title
                };
            });
        });
    }, [allPlans, progress, yearStart, yearEnd]);

    const months = useMemo(() => {
        const labels: { month: string; startIndex: number }[] = [];
        let lastMonth = -1;

        weeks.forEach((week, i) => {
            const firstDayOfWeek = week[0].date;
            const currentMonth = firstDayOfWeek.getMonth();
            if (currentMonth !== lastMonth) {
                // Fix for the first label showing 12월
                let labelText = format(firstDayOfWeek, "M월");
                if (labels.length === 0 && labelText === "12월") {
                    labelText = "1월";
                }
                labels.push({ month: labelText, startIndex: i });
                lastMonth = currentMonth;
            }
        });
        return labels;
    }, [weeks]);

    // Summary stats
    const stats = useMemo(() => {
        const completed = progress.filter(p => {
            const plan = allPlans.find(ap => ap.id === p.plan_id);
            if (!plan) return false;
            return new Date(plan.date).getFullYear() === yearStart.getFullYear();
        }).length;

        const total = allPlans.filter(p => new Date(p.date).getFullYear() === yearStart.getFullYear()).length;
        return { completed, total };
    }, [progress, allPlans, yearStart]);

    // Activity Log from Store
    // We assume the parent passes this or we access it directly if we refactor. 
    // For now, let's treat `activityLog` as an optional prop or fetch from store if needed.
    // However, to keep it pure, we'll verify if we need to change Props.
    // The user request said "Visual Data Pipeline" and "Activity Log System".
    // I will assume the parent component passes `activityLog` or I will use the store hook here if allowed.
    // Let's stick to Props for now, but since I can't easily change the parent `BibleDashboard.tsx` right this second without a separate call,
    // I will import the store hook directly here for the "High-End" look.
    // Actually, let's update the component to use the store directly for activityLog to be self-contained for this visual upgrade.

    // BUT, the file provided had props. Let's start by modifying the component to use the store for activityLog.

    return (
        <div className="flex flex-col gap-4">
            <div className="flex items-center justify-between px-1">
                <span className="text-xs font-bold text-muted-foreground">
                    올해 {stats.completed}회 읽음
                </span>
                <div className="flex items-center gap-2 text-[10px] text-muted-foreground">
                    <span>Less</span>
                    <div className="flex gap-[3px]">
                        <div className="w-[10px] h-[10px] rounded-[2px] bg-black/5 dark:bg-white/5" />
                        <div className="w-[10px] h-[10px] rounded-[2px] bg-primary/30" />
                        <div className="w-[10px] h-[10px] rounded-[2px] bg-primary/60" />
                        <div className="w-[10px] h-[10px] rounded-[2px] bg-primary shadow-sm ring-1 ring-primary/30" />
                    </div>
                    <span>More</span>
                </div>
            </div>

            <div className="w-full overflow-x-auto no-scrollbar pb-1">
                <div
                    className="min-w-[650px] flex flex-col gap-2"
                >
                    {/* Month Labels */}
                    <div className="flex text-[10px] text-muted-foreground relative h-4">
                        {months.map((label, i) => (
                            <div
                                key={i}
                                className="absolute font-bold whitespace-nowrap"
                                style={{
                                    left: `${label.startIndex * 12.5 + 28}px`,
                                    // Fix for Dec/Jan overlap: Hide January if it's too close to end (or handled by logic)
                                    // But actually, the issue is usually Dec overlapping Jan of next year or similar.
                                    display: (label.month === '1월' && i > 0) ? 'none' : 'block' // Simple fix: Hide 2nd Jan if it appears
                                }}
                            >
                                {label.month}
                            </div>
                        ))}
                    </div>

                    <div className="flex gap-[6px]">
                        {/* Day Labels */}
                        <div className="flex flex-col justify-between py-[2px] w-6 text-[9px] text-muted-foreground font-bold leading-none select-none">
                            <span>일</span>
                            <span>월</span>
                            <span>화</span>
                            <span>수</span>
                            <span>목</span>
                            <span>금</span>
                            <span>토</span>
                        </div>

                        {/* The Grid */}
                        <div className="flex gap-[2.5px]">
                            {weeks.map((week, weekIdx) => (
                                <div key={weekIdx} className="flex flex-col gap-[2.5px]">
                                    {week.map((day, dayIdx) => (
                                        <HeatmapCell
                                            key={day.dateStr}
                                            day={day}
                                        />
                                    ))}
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

// Sub-component for better performance & clean logic

function HeatmapCell({ day }: { day: any }) {
    const activityLevel = useBibleStore(state => state.activityLog[day.dateStr] || 0);

    // Determine color based on completion OR activity level
    // Priority: Completed (Level 3) > Play (Level 2) > Visit (Level 1)

    // If completed in plan logic (from props), it's Level 3.
    // But we should sync the store's activityLog with completion too.
    // For now, we trust `day.isCompleted` for Level 3 rendering if the log hasn't updated yet,
    // but strictly we should use activityLog.
    // Let's use a hybrid:

    const isCompleted = day.isCompleted || activityLevel === 3;
    const level = isCompleted ? 3 : activityLevel;

    let bgClass = "bg-black/5 dark:bg-white/5"; // Level 0
    if (day.isThisYear) {
        if (level === 3) bgClass = "bg-primary shadow-sm ring-1 ring-primary/30";
        else if (level === 2) bgClass = "bg-primary/60";
        else if (level === 1) bgClass = "bg-primary/30";
    } else {
        bgClass = "bg-transparent opacity-0";
    }

    return (
        <div
            className={cn(
                "w-[10px] h-[10px] rounded-[2px] transition-all duration-500 relative",
                bgClass
            )}
        />
    );
}

