"use client";

import { useState, useMemo, useEffect, useCallback } from "react";
import {
    Moon, Sun, Trash2, Download, Upload, BookOpen,
    ChevronRight, Youtube, Clock, Type,
    Bell, BellOff, Share2, Award, Heart, Sparkles, Unlock,
    Volume2, VolumeX, Settings as SettingsIcon, AlertTriangle, FileJson,
    Calendar as CalendarIcon, Repeat, Tag, MessageSquare
} from "lucide-react";
import { useTheme } from "next-themes";
import { SmartCard } from "@/components/ui/smart-card";
import { cn } from "@/lib/utils";
import {
    loadNotificationSettings,
    saveNotificationSettings,
    scheduleDailyNotifications,
    cancelAllDailyNotifications,
    NotificationSettings,
    DEFAULT_SETTINGS,
} from "@/lib/notification-service";
import {
    loadShareSettings,
    saveShareSettings,
    scheduleShareReminder,
    cancelShareReminders,
    shareContent,
    shareViaSMS,
    shareViaKakao,
    ShareSettings,
    DEFAULT_SHARE_SETTINGS,
    ShareFrequency,
    ShareChannel
} from "@/lib/share-service";
import WidgetPreview from "./WidgetPreview";
import { BibleReadingPlan, UserProgress } from "@/types/bible";
import WidgetDataBridge from "@/lib/widget-bridge";
import { Phone, X, RefreshCw } from "lucide-react";
import { AnimatePresence, motion } from "framer-motion";

// --- Toggle Switch ---
function ToggleSwitch({ checked, onCheckedChange, showIcon = false }: { checked: boolean; onCheckedChange: (c: boolean) => void; showIcon?: boolean }) {
    return (
        <button
            onClick={() => onCheckedChange(!checked)}
            className={cn(
                "w-12 h-7 rounded-full transition-all duration-300 relative shadow-inner",
                checked
                    ? "bg-gradient-to-r from-primary to-primary/80"
                    : "bg-muted dark:bg-muted/50"
            )}
        >
            <div className={cn(
                "absolute top-0.5 w-6 h-6 rounded-full bg-white shadow-md transition-all duration-300 flex items-center justify-center",
                checked ? "left-[22px]" : "left-0.5"
            )}>
                {showIcon && (checked ? <Sun size={12} className="text-primary" /> : <Moon size={12} className="text-muted-foreground" />)}
            </div>
        </button>
    );
}

// --- Option Selector ---
function OptionSelector({ options, value, onChange }: {
    options: { id: string; label: string; icon?: React.ReactNode }[];
    value: string;
    onChange: (v: string) => void;
}) {
    return (
        <div className="flex gap-1.5 p-1 bg-muted/30 rounded-xl">
            {options.map(opt => (
                <button
                    key={opt.id}
                    onClick={() => onChange(opt.id)}
                    className={cn(
                        "flex-1 flex items-center justify-center gap-1.5 px-3 py-2 rounded-lg text-xs font-bold transition-all duration-300",
                        value === opt.id
                            ? "bg-primary text-primary-foreground shadow-sm"
                            : "text-muted-foreground hover:text-foreground hover:bg-muted/50"
                    )}
                >
                    {opt.icon}
                    {opt.label}
                </button>
            ))}
        </div>
    );
}

interface SettingsViewProps {
    onReschedule?: () => void;
    progress?: UserProgress[];
    allPlans?: BibleReadingPlan[];
    streak?: number;
    onTabChange?: (tab: string) => void;
}

export default function SettingsView({ onReschedule, progress = [], allPlans = [], streak = 0, onTabChange }: SettingsViewProps) {
    const { theme, setTheme, resolvedTheme } = useTheme();
    // Swipe Logic
    const [touchStart, setTouchStart] = useState<number | null>(null);
    const [touchEnd, setTouchEnd] = useState<number | null>(null);

    const onTouchStart = (e: React.TouchEvent) => {
        setTouchEnd(null);
        setTouchStart(e.targetTouches[0].clientX);
    };

    const onTouchEnd = (e: React.TouchEvent) => {
        setTouchEnd(e.changedTouches[0].clientX);
        if (!touchStart) return;
        const distance = e.changedTouches[0].clientX - touchStart;
        const isRightSwipe = distance > 100;
        if (isRightSwipe && onTabChange) {
            onTabChange('home');
        }
    };

    const [mounted, setMounted] = useState(false);
    const [confirmReset, setConfirmReset] = useState(false);
    const [fontSize, setFontSize] = useState(() =>
        typeof window !== 'undefined' ? localStorage.getItem('bible_font_size') || 'medium' : 'medium'
    );
    const [autoPlay, setAutoPlay] = useState(() =>
        typeof window !== 'undefined' ? localStorage.getItem('bible_autoplay') === 'true' : false
    );
    const [dailyVerse, setDailyVerse] = useState(() =>
        typeof window !== 'undefined' ? localStorage.getItem('bible_daily_verse') !== 'false' : true
    );
    const [autoBackup, setAutoBackup] = useState(() =>
        typeof window !== 'undefined' ? localStorage.getItem('bible_auto_backup') !== 'false' : true
    );
    const [showKeywords, setShowKeywords] = useState(() =>
        typeof window !== 'undefined' ? localStorage.getItem('bible_show_keywords') !== 'false' : true
    );
    const [requireReflection, setRequireReflection] = useState(() =>
        typeof window !== 'undefined' ? localStorage.getItem('bible_require_reflection') !== 'false' : true
    );
    const [streakMode, setStreakMode] = useState(() =>
        typeof window !== 'undefined' ? localStorage.getItem('bible_streak_mode') || 'day' : 'day'
    );
    const [lockScreenPopup, setLockScreenPopup] = useState(() =>
        typeof window !== 'undefined' ? localStorage.getItem('bible_lock_screen') === 'true' : false
    );
    const [lockScreenStartTime, setLockScreenStartTime] = useState(() =>
        typeof window !== 'undefined' ? parseInt(localStorage.getItem('bible_lock_screen_start') || '0', 10) : 0
    );
    const [lockScreenEndTime, setLockScreenEndTime] = useState(() =>
        typeof window !== 'undefined' ? parseInt(localStorage.getItem('bible_lock_screen_end') || '23', 10) : 23
    );
    const [lockScreenMaxImpressions, setLockScreenMaxImpressions] = useState(() =>
        typeof window !== 'undefined' ? parseInt(localStorage.getItem('bible_lock_screen_max') || '0', 10) : 0
    );

    // Notification settings state
    const [notifSettings, setNotifSettings] = useState<NotificationSettings>(DEFAULT_SETTINGS);
    const [shareSettings, setShareSettings] = useState<ShareSettings>(DEFAULT_SHARE_SETTINGS);
    const [newPhone, setNewPhone] = useState("");

    useEffect(() => {
        setMounted(true);
        setNotifSettings(loadNotificationSettings());
        setShareSettings(loadShareSettings());
    }, []);

    const updateNotifSetting = useCallback(async <K extends keyof NotificationSettings>(
        key: K,
        value: NotificationSettings[K]
    ) => {
        const updated = { ...notifSettings, [key]: value };
        setNotifSettings(updated);
        saveNotificationSettings(updated);
        if (updated.enabled) {
            await scheduleDailyNotifications(updated);
        } else {
            await cancelAllDailyNotifications();
        }
    }, [notifSettings]);

    const updateShareSetting = useCallback(async <K extends keyof ShareSettings>(
        key: K,
        value: ShareSettings[K]
    ) => {
        const updated = { ...shareSettings, [key]: value };
        setShareSettings(updated);
        saveShareSettings(updated);
        if (updated.enabled) {
            await scheduleShareReminder(updated);
        } else {
            await cancelShareReminders();
        }
    }, [shareSettings]);

    // Stats from localStorage
    const stats = useMemo(() => {
        if (typeof window === 'undefined') return { total: 0, streak: 0, startDate: '' };
        try {
            const data = localStorage.getItem('guest_bible_progress');
            const parsed = data ? JSON.parse(data) : [];
            const total = Array.isArray(parsed) ? parsed.length : 0;
            return { total, streak: 0, startDate: '2026.01.01' };
        } catch {
            return { total: 0, streak: 0, startDate: '' };
        }
    }, []);

    const handleFontSizeChange = (size: string) => {
        setFontSize(size);
        localStorage.setItem('bible_font_size', size);
        // Apply CSS variable globally + notify other components
        const scales: Record<string, string> = { small: '0.88', medium: '1', large: '1.15' };
        document.documentElement.style.setProperty('--font-scale', scales[size] || '1');
        window.dispatchEvent(new CustomEvent('bible-font-change'));
    };

    const handleAutoPlayChange = (val: boolean) => {
        setAutoPlay(val);
        localStorage.setItem('bible_autoplay', String(val));
    };

    const handleDailyVerseChange = (val: boolean) => {
        setDailyVerse(val);
        localStorage.setItem('bible_daily_verse', String(val));
    };

    const handleAutoBackupChange = (val: boolean) => {
        setAutoBackup(val);
        localStorage.setItem('bible_auto_backup', String(val));
    };

    const handleShowKeywordsChange = (val: boolean) => {
        setShowKeywords(val);
        localStorage.setItem('bible_show_keywords', String(val));
        window.dispatchEvent(new Event('bible_settings_changed'));
    };

    const handleRequireReflectionChange = (val: boolean) => {
        setRequireReflection(val);
        localStorage.setItem('bible_require_reflection', String(val));
        window.dispatchEvent(new Event('bible_settings_changed'));
    };

    const handleStreakModeChange = (val: string) => {
        setStreakMode(val);
        localStorage.setItem('bible_streak_mode', val);
        window.dispatchEvent(new Event('bible_streak_mode_change'));
    };

    const syncLockScreenWidget = async (enabled: boolean, start: number, end: number, max: number) => {
        try {
            const widgetData = {
                title: allPlans[0]?.title || "오늘의 성경 읽기",
                verse: "말씀을 묵상하며 하루를 시작하세요.",
                progress: Math.round((progress.length / (allPlans.length || 365)) * 100),
                streak: streak,
                date: new Date().toLocaleDateString('ko-KR', { month: 'long', day: 'numeric' }),
                isLockScreenEnabled: enabled,
                lockScreenStartTime: start,
                lockScreenEndTime: end,
                lockScreenMaxImpressions: max
            };
            await WidgetDataBridge.updateWidgetData(widgetData);
        } catch (e) {
            console.error(e);
        }
    };

    const handleLockScreenPopupChange = async (val: boolean) => {
        if (val) {
            try {
                const { granted } = await WidgetDataBridge.checkOverlayPermission();
                if (!granted) {
                    const confirm = window.confirm("화면을 켤 때마다 자동으로 띄우려면 '다른 앱 위에 표시' 권한이 꼭 필요합니다. 설정으로 이동하시겠습니까?");
                    if (confirm) {
                        await WidgetDataBridge.requestOverlayPermission();
                    }
                }
            } catch (e) {
                console.error("Overlay permission check failed:", e);
            }
        }
        setLockScreenPopup(val);
        localStorage.setItem('bible_lock_screen', String(val));
        await syncLockScreenWidget(val, lockScreenStartTime, lockScreenEndTime, lockScreenMaxImpressions);
    };

    const handleLockScreenTimeChange = async (type: 'start' | 'end', val: number) => {
        if (type === 'start') {
            setLockScreenStartTime(val);
            localStorage.setItem('bible_lock_screen_start', String(val));
            await syncLockScreenWidget(lockScreenPopup, val, lockScreenEndTime, lockScreenMaxImpressions);
        } else {
            setLockScreenEndTime(val);
            localStorage.setItem('bible_lock_screen_end', String(val));
            await syncLockScreenWidget(lockScreenPopup, lockScreenStartTime, val, lockScreenMaxImpressions);
        }
    };

    const handleLockScreenMaxChange = async (val: number) => {
        setLockScreenMaxImpressions(val);
        localStorage.setItem('bible_lock_screen_max', String(val));
        await syncLockScreenWidget(lockScreenPopup, lockScreenStartTime, lockScreenEndTime, val);
    };

    const handleReset = () => {
        if (confirmReset) {
            localStorage.removeItem('guest_bible_progress');
            window.location.reload();
        } else {
            setConfirmReset(true);
            setTimeout(() => setConfirmReset(false), 3000);
        }
    };

    const handleExport = () => {
        const data = localStorage.getItem('guest_bible_progress');
        if (!data) return;
        const blob = new Blob([JSON.stringify({ progress: JSON.parse(data), exportDate: new Date().toISOString(), version: "1.2.0" }, null, 2)], { type: "application/json" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `성경365-백업-${new Date().toISOString().slice(0, 10)}.json`;
        a.click();
        URL.revokeObjectURL(url);
    };

    const handleImportClick = () => {
        document.getElementById('import-file')?.click();
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const json = JSON.parse(event.target?.result as string);
                if (json.progress && Array.isArray(json.progress)) {
                    if (confirm(`📅 ${json.exportDate?.slice(0, 10) || '불명'}의 데이터로 복원하시겠습니까?\n총 ${json.progress.length}일의 읽기 기록이 있습니다.`)) {
                        localStorage.setItem('guest_bible_progress', JSON.stringify(json.progress));
                        alert("✅ 복원이 완료되었습니다.");
                        window.location.reload();
                    }
                } else {
                    alert("❌ 올바른 백업 파일이 아닙니다.");
                }
            } catch (err) {
                alert("❌ 파일 읽기 실패: " + err);
            }
        };
        reader.readAsText(file);
    };

    const handleAddPhone = () => {
        if (!newPhone) return;
        const currentPhones = shareSettings.recipientPhones || [];
        if (!currentPhones.includes(newPhone)) {
            updateShareSetting('recipientPhones', [...currentPhones, newPhone]);
        }
        setNewPhone("");
    };

    const handleRemovePhone = (phone: string) => {
        const currentPhones = shareSettings.recipientPhones || [];
        updateShareSetting('recipientPhones', currentPhones.filter(p => p !== phone));
    };

    const handleForceWidgetSync = async () => {
        try {
            await syncLockScreenWidget(lockScreenPopup, lockScreenStartTime, lockScreenEndTime, lockScreenMaxImpressions);
            alert("✅ 위젯 데이터가 동기화되었습니다!");
        } catch (e) {
            console.error(e);
            alert("❌ 위젯 동기화 실패: " + e);
        }
    };

    if (!mounted) return null;



    if (!mounted) return null;

    return (
        <div
            className="animate-in fade-in slide-in-from-right-4 duration-500 pb-20 pt-12 space-y-8"
            onTouchStart={onTouchStart}
            onTouchEnd={onTouchEnd}
        >
            {/* Header Removed as requested */}

            {/* === My Journey Stats Banner === */}
            <SmartCard variant="elevated" className="bg-gradient-to-br from-primary/5 via-background to-primary/5 border border-primary/10 dark:border-primary/20">
