                    action={
                        <ToggleSwitch checked={autoPlay} onCheckedChange={handleAutoPlayChange} />
                    }
                />
                <SettingRow
                    icon={Heart}
                    iconColor="text-rose-500"
                    iconBg="bg-rose-500/10"
                    label="격려 메시지"
