                    action={
                        <ToggleSwitch checked={dailyVerse} onCheckedChange={handleDailyVerseChange} />
                    }
                />
                <SettingRow
                    icon={Tag}
                    iconColor="text-blue-500"
                    iconBg="bg-blue-500/10"
                    label="묵상 키워드 표시"
                    description="홈 화면 본문 아래에 핵심 단어 해시태그를 표시합니다"
                    action={
                        <ToggleSwitch checked={showKeywords} onCheckedChange={handleShowKeywordsChange} />
                    }
                />
                <SettingRow
                    icon={MessageSquare}
                    iconColor="text-emerald-500"
                    iconBg="bg-emerald-500/10"
                    label="읽기 완료 팝업"
                    description="읽기 완료 체크 시 묵상일지 작성 팝업을 바로 띄웁니다. 끄면 자동 스킵됩니다."
                    action={
                        <ToggleSwitch checked={requireReflection} onCheckedChange={handleRequireReflectionChange} />
                    }
                />
            </Section>

            {/* === Lock Screen Notification === */}
            <Section title="알림" icon={<Bell size={14} />}>
