                                <select
                                    className="bg-muted/40 rounded-lg py-1 px-1.5 text-xs font-bold text-foreground outline-none border border-border/50"
                                    value={lockScreenEndTime}
                                    onChange={(e) => handleLockScreenTimeChange('end', parseInt(e.target.value))}
                                >
                                    {Array.from({ length: 24 }).map((_, i) => (
                                        <option key={i} value={i}>{`${i}시`}</option>
