                                <div className="leading-tight">
                                    <p className="text-sm font-semibold text-foreground">1일 노출 횟수</p>
                                    <p className="text-[10px] text-muted-foreground mt-0.5">하루 최대 노출 횟수를 지정합니다</p>
                                </div>
                            </div>
                            <select
                                className="bg-muted/40 rounded-lg py-1 px-2 text-xs font-bold text-foreground outline-none border border-border/50"
                                value={lockScreenMaxImpressions}
                                onChange={(e) => handleLockScreenMaxChange(parseInt(e.target.value))}
                            >
                                <option value={1}>1번</option>
                                <option value={3}>3번</option>
                                <option value={0}>제한없음</option>
                            </select>
                        </div>
                    </div>
                )}
                <SettingRow
                    icon={notifSettings.enabled ? Bell : BellOff}
                    iconColor={notifSettings.enabled ? "text-blue-500" : "text-muted-foreground"}
                    iconBg={notifSettings.enabled ? "bg-blue-500/10" : "bg-muted/30"}
                    label="알림"
                    description="매일 지정한 시간에 읽기 알림을 표시합니다"
                    action={
                        <ToggleSwitch
                            checked={notifSettings.enabled}
                            onCheckedChange={(c) => updateNotifSetting('enabled', c)}
                        />
                    }
                />

                {notifSettings.enabled && (
                    <>
                        {/* Time Picker */}
                        <div className="pl-6 px-4 py-3.5">
                            <div className="flex items-center justify-between mb-3">
                                <div className="flex items-center gap-3.5">
                                    <div className="p-2 rounded-xl bg-indigo-500/10">
                                        <Clock size={16} className="text-indigo-500" />
                                    </div>
                                    <div>
                                        <p className="text-sm font-semibold text-foreground">알림 시간</p>
                                        <p className="text-[10px] text-muted-foreground mt-0.5">매일 이 시간에 알림이 표시됩니다</p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-1 bg-muted/40 rounded-xl px-1 py-1">
                                    <select
                                        value={notifSettings.hour}
                                        onChange={(e) => updateNotifSetting('hour', parseInt(e.target.value))}
                                        className="bg-transparent text-center text-lg font-bold text-foreground appearance-none cursor-pointer w-10 outline-none"
                                    >
                                        {Array.from({ length: 24 }, (_, i) => (
                                            <option key={i} value={i}>{String(i).padStart(2, '0')}</option>
                                        ))}
                                    </select>
                                    <span className="text-lg font-bold text-muted-foreground">:</span>
                                    <select
                                        value={notifSettings.minute}
                                        onChange={(e) => updateNotifSetting('minute', parseInt(e.target.value))}
                                        className="bg-transparent text-center text-lg font-bold text-foreground appearance-none cursor-pointer w-10 outline-none"
                                    >
                                        {Array.from({ length: 12 }, (_, i) => i * 5).map(m => (
                                            <option key={m} value={m}>{String(m).padStart(2, '0')}</option>
                                        ))}
                                    </select>
                                </div>
                            </div>

                            {/* Preset Buttons */}
                            <div className="flex gap-1.5 p-1 bg-muted/30 rounded-xl">
                                {[
                                    { label: '🌅 새벽', h: 5, m: 30 },
                                    { label: '☀️ 아침', h: 7, m: 0 },
                                    { label: '🌙 저녁', h: 21, m: 0 },
                                ].map(preset => {
                                    const isActive = notifSettings.hour === preset.h && notifSettings.minute === preset.m;
                                    return (
                                        <button
                                            key={preset.label}
                                            onClick={() => {
                                                const updated = { ...notifSettings, hour: preset.h, minute: preset.m };
                                                setNotifSettings(updated);
                                                saveNotificationSettings(updated);
                                                if (updated.enabled) scheduleDailyNotifications(updated);
                                            }}
                                            className={cn(
                                                "flex-1 px-3 py-2 rounded-lg text-xs font-bold transition-all duration-300",
                                                isActive
                                                    ? "bg-primary text-primary-foreground shadow-sm"
                                                    : "text-muted-foreground hover:text-foreground hover:bg-muted/50"
                                            )}
                                        >
                                            {preset.label}
                                        </button>
                                    );
                                })}
                            </div>
                        </div>

                        {/* Day Selector */}
                        <div className="pl-6 px-4 py-3.5 border-t border-border/30 dark:border-white/5">
                            <p className="text-xs font-bold text-muted-foreground mb-2.5">반복 요일</p>
                            <div className="flex gap-1">
                                {['월', '화', '수', '목', '금', '토', '일'].map((day, idx) => (
                                    <button
                                        key={day}
                                        onClick={() => {
                                            const newDays = [...notifSettings.days];
                                            newDays[idx] = !newDays[idx];
                                            // Prevent deselecting all
                                            if (newDays.some(d => d)) {
                                                updateNotifSetting('days', newDays);
                                            }
                                        }}
                                        className={cn(
                                            "flex-1 py-2 rounded-lg text-xs font-bold transition-all duration-300",
                                            notifSettings.days[idx]
                                                ? "bg-primary text-primary-foreground shadow-sm"
                                                : "bg-muted/30 text-muted-foreground hover:bg-muted/50"
                                        )}
                                    >
                                        {day}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Content Preview Toggle */}
                        <SettingRow
                            icon={BookOpen}
                            iconColor="text-emerald-500"
                            iconBg="bg-emerald-500/10"
                            label="구절 미리보기"
                            description="알림에 오늘의 읽기 구절을 표시합니다"
                            action={
                                <ToggleSwitch
                                    checked={notifSettings.showPreview}
                                    onCheckedChange={(c) => updateNotifSetting('showPreview', c)}
                                />
                            }
                        />

                        {/* Sound Toggle */}
                        <SettingRow
                            icon={notifSettings.silent ? VolumeX : Volume2}
                            iconColor={notifSettings.silent ? "text-muted-foreground" : "text-purple-500"}
                            iconBg={notifSettings.silent ? "bg-muted/30" : "bg-purple-500/10"}
                            label="무음 알림"
                            description="소리 없이 조용히 알림을 표시합니다"
                            action={
                                <ToggleSwitch
                                    checked={notifSettings.silent}
                                    onCheckedChange={(c) => updateNotifSetting('silent', c)}
                                />
                            }
                        />
                    </>
                )}
            </Section>

            {/* === Share & Community === */}
            <Section title="공유 및 연결" icon={<Share2 size={14} />}>
                <SettingRow
                    icon={Share2}
                    iconColor="text-blue-500"
                    iconBg="bg-blue-500/10"
                    label="지금 공유하기"
                    description="친구들에게 성경 읽기를 추천합니다"
                    onClick={() => shareContent("성경 365", "함께 성경 읽기에 도전해요! 매일 조금씩 읽다보면 1년에 1독을 할 수 있습니다.", "https://bible-365-app.vercel.app")}
                />

                {/* Automation Share */}
                <SettingRow
                    icon={shareSettings.enabled ? Repeat : CalendarIcon}
                    iconColor={shareSettings.enabled ? "text-pink-500" : "text-muted-foreground"}
                    iconBg={shareSettings.enabled ? "bg-pink-500/10" : "bg-muted/30"}
                    label="자동 공유 예약"
                    description="정기적으로 공유 알림을 받습니다"
                    action={
                        <ToggleSwitch
                            checked={shareSettings.enabled}
                            onCheckedChange={(c) => updateShareSetting('enabled', c)}
                        />
                    }
                />

                {shareSettings.enabled && (
                    <div className="pl-6 px-4 pb-4 space-y-4 animate-in slide-in-from-top-2 duration-300">
                        {/* Frequency Selector */}
                        <div>
                            <p className="text-xs font-bold text-muted-foreground mb-2">예약 주기</p>
                            <div className="flex gap-1 p-1 bg-muted/30 rounded-xl">
                                {[
                                    { id: 'daily', label: '매일' },
                                    { id: 'weekly', label: '매주' },
                                    { id: 'monthly', label: '매월' },
                                    { id: 'yearly', label: '매년' }
                                ].map(freq => (
                                    <button
                                        key={freq.id}
                                        onClick={() => updateShareSetting('frequency', freq.id as ShareFrequency)}
                                        className={cn(
                                            "flex-1 py-1.5 rounded-lg text-xs font-bold transition-all",
                                            shareSettings.frequency === freq.id
                                                ? "bg-primary text-primary-foreground shadow-sm"
                                                : "text-muted-foreground hover:bg-muted/50"
                                        )}
                                    >
                                        {freq.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Dynamic Inputs based on Frequency */}
                        <div className="flex gap-3">
                            {/* Weekday Selector (Weekly) */}
                            {shareSettings.frequency === 'weekly' && (
                                <div className="flex-1">
                                    <p className="text-xs font-bold text-muted-foreground mb-2">요일 선택</p>
                                    <select
                                        value={shareSettings.weekday || 2}
                                        onChange={(e) => updateShareSetting('weekday', parseInt(e.target.value))}
                                        className="w-full bg-muted/30 rounded-lg px-3 py-2 text-sm font-bold outline-none"
                                    >
                                        <option value={2}>월요일</option>
                                        <option value={3}>화요일</option>
                                        <option value={4}>수요일</option>
                                        <option value={5}>목요일</option>
                                        <option value={6}>금요일</option>
                                        <option value={7}>토요일</option>
                                        <option value={1}>일요일</option>
                                    </select>
