                                    <p className="text-xs font-bold text-muted-foreground mb-2">날짜 선택</p>
                                    <select
                                        value={shareSettings.dayOfMonth || 1}
                                        onChange={(e) => updateShareSetting('dayOfMonth', parseInt(e.target.value))}
                                        className="w-full bg-muted/30 rounded-lg px-3 py-2 text-sm font-bold outline-none"
                                    >
