                                            <option key={d} value={d}>{d}일</option>
                                        ))}
                                    </select>
                                </div>
                            )}

                            {/* Month (Yearly) */}
                            {shareSettings.frequency === 'yearly' && (
                                <div className="flex-1">
                                    <p className="text-xs font-bold text-muted-foreground mb-2">월 선택</p>
                                    <select
                                        value={shareSettings.month || 1}
                                        onChange={(e) => updateShareSetting('month', parseInt(e.target.value))}
                                        className="w-full bg-muted/30 rounded-lg px-3 py-2 text-sm font-bold outline-none"
                                    >
                                        {Array.from({ length: 12 }, (_, i) => i + 1).map(m => (
                                            <option key={m} value={m}>{m}월</option>
