                                    <select
                                        value={shareSettings.hour}
                                        onChange={(e) => updateShareSetting('hour', parseInt(e.target.value))}
                                        className="bg-transparent text-center font-bold outline-none w-12 appearance-none" style={{ textAlignLast: 'center' }}
