// --- Section Component ---
function Section({ title, icon, children }: { title: string; icon?: React.ReactNode; children: React.ReactNode }) {
    return (
        <div className="space-y-3">
            <h3 className="px-2 text-xs font-bold text-muted-foreground uppercase tracking-widest flex items-center gap-2">
                {icon} {title}
            </h3>
            <SmartCard
                variant="elevated"
                padding="none"
                className="bg-card/50 backdrop-blur-sm border border-border/50 dark:border-white/10 overflow-hidden divide-y divide-border/30 dark:divide-white/5"
            >
                {children}
            </SmartCard>
        </div>
    );
}

// --- Setting Row Component ---
function SettingRow({
    icon: Icon,
    iconColor = "text-primary",
    iconBg = "bg-primary/10",
    label,
    description,
    action,
    onClick,
    externalLink,
    destructive
}: {
    icon: any;
    iconColor?: string;
    iconBg?: string;
    label: string;
    description?: string;
    action?: React.ReactNode;
    onClick?: () => void;
    externalLink?: string;
    destructive?: boolean;
}) {
    const isClickable = onClick || externalLink;

    return (
        <div
            className={cn(
                "flex items-center justify-between px-4 py-3.5 transition-colors",
                isClickable && "hover:bg-muted/30 cursor-pointer active:bg-muted/50"
            )}
            onClick={() => {
                if (onClick) onClick();
                if (externalLink) window.open(externalLink, '_blank');
            }}
        >
            <div className="flex items-center gap-3.5 min-w-0">
                <div className={cn("p-2 rounded-xl shrink-0", iconBg)}>
                    <Icon size={16} className={iconColor} />
                </div>
                <div className="min-w-0">
                    <p className={cn(
                        "text-sm font-semibold truncate",
                        destructive ? "text-destructive" : "text-foreground"
                    )}>{label}</p>
                    {description && (
                        <p className="text-[10px] text-muted-foreground truncate mt-0.5">{description}</p>
                    )}
                </div>
            </div>
            <div className="shrink-0 ml-3">
                {action || (isClickable && <ChevronRight size={16} className="text-muted-foreground/50" />)}
            </div>
        </div>
    );
}

"use client";

import { useMemo, useState, useCallback } from "react";
import { Flame, TrendingUp, Calendar, Trophy, XCircle, Snowflake, Zap, Target, Clock, BarChart3 } from "lucide-react";
import { cn } from "@/lib/utils";
import { SmartCard } from "@/components/ui/smart-card";
import { UserProgress } from "@/types/bible";
import { calculateStreak } from "@/lib/stats";

interface StreakHistoryViewProps {
    progress: UserProgress[];
    onBack: () => void;
}

interface StreakPeriod {
    type: 'streak' | 'gap';
    startDate: string;
    endDate: string;
    days: number;
}

function formatDate(dateStr: string): string {
    const d = new Date(dateStr);
    return `${d.getMonth() + 1}/${d.getDate()}`;
}

function formatDateFull(dateStr: string): string {
    const d = new Date(dateStr);
    return `${d.getFullYear()}.${String(d.getMonth() + 1).padStart(2, '0')}.${String(d.getDate()).padStart(2, '0')}`;
}

function addDays(dateStr: string, n: number): string {
    const [y, m, d] = dateStr.split('-').map(Number);
    const date = new Date(y, m - 1, d);
    date.setDate(date.getDate() + n);
    return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
}

function diffDays(a: string, b: string): number {
    const [y1, m1, d1] = a.split('-').map(Number);
    const [y2, m2, d2] = b.split('-').map(Number);
    const d_a = Date.UTC(y1, m1 - 1, d1);
    const d_b = Date.UTC(y2, m2 - 1, d2);
    return Math.round((d_b - d_a) / 86400000);
}

function toDateStr(d: Date): string {
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
}

// === Sub-Tab Type ===
type SubTab = 'overview' | 'heatmap' | 'history';

// === Main Component ===
export default function StreakHistoryView({ progress, onBack }: StreakHistoryViewProps) {
    const [subTab, setSubTab] = useState<SubTab>('overview');

    const { periods, stats, readDatesSet, weeklyInsights, freezeCount } = useMemo(() => {
        const dates = Array.from(new Set(
            progress
                .map(p => p.reading_plan?.date)
                .filter((d): d is string => !!d)
        )).sort();

        const readDatesSet = new Set(dates);

        if (dates.length === 0) {
            return {
                periods: [] as StreakPeriod[],
                stats: { current: 0, best: 0, total: 0, avgStreak: 0 },
                readDatesSet,
                weeklyInsights: { thisWeekDays: 0, lastWeekDays: 0, bestWeekday: '', comebackCount: 0 },
                freezeCount: 0,
            };
        }

        // Build streak periods
        const periods: StreakPeriod[] = [];
        let streakStart = dates[0];
        let prevDate = dates[0];
        for (let i = 1; i < dates.length; i++) {
            const gap = diffDays(prevDate, dates[i]);
            if (gap === 1) {
                prevDate = dates[i];
            } else {
                periods.push({
                    type: 'streak',
                    startDate: streakStart,
                    endDate: prevDate,
                    days: diffDays(streakStart, prevDate) + 1,
                });
                if (gap > 1) {
                    periods.push({
                        type: 'gap',
                        startDate: addDays(prevDate, 1),
                        endDate: addDays(dates[i], -1),
                        days: gap - 1,
                    });
                }
                streakStart = dates[i];
                prevDate = dates[i];
            }
        }
        periods.push({
            type: 'streak',
            startDate: streakStart,
            endDate: prevDate,
            days: diffDays(streakStart, prevDate) + 1,
        });

        const streakPeriods = periods.filter(p => p.type === 'streak');
        const best = streakPeriods.length > 0 ? Math.max(...streakPeriods.map(p => p.days)) : 0;
        const avgStreak = streakPeriods.length > 0
            ? Math.round(streakPeriods.reduce((a, p) => a + p.days, 0) / streakPeriods.length)
            : 0;
        const rawDates = progress.map(p => p.reading_plan?.date).filter((d): d is string => !!d);
        const current = calculateStreak(rawDates);

        // Weekly insights
        const now = new Date();
        const startOfWeek = new Date(now);
        startOfWeek.setDate(now.getDate() - now.getDay());
        const startOfLastWeek = new Date(startOfWeek);
        startOfLastWeek.setDate(startOfLastWeek.getDate() - 7);

        let thisWeekDays = 0;
        let lastWeekDays = 0;
        const weekdayCounts = [0, 0, 0, 0, 0, 0, 0]; // Sun-Sat

        dates.forEach(dateStr => {
            const d = new Date(dateStr);
            weekdayCounts[d.getDay()]++;
            if (d >= startOfWeek) thisWeekDays++;
            else if (d >= startOfLastWeek) lastWeekDays++;
        });

        const dayNames = ['일', '월', '화', '수', '목', '금', '토'];
        const maxIdx = weekdayCounts.indexOf(Math.max(...weekdayCounts));
        const bestWeekday = dayNames[maxIdx] + '요일';

        // Comeback count: how many times streak broke and restarted next day
        let comebackCount = 0;
        for (let i = 0; i < periods.length - 1; i++) {
            if (periods[i].type === 'gap' && periods[i].days === 1) comebackCount++;
        }

        // Freeze system: earn 1 per 7-day streak, +2 per 30-day, +3 per 90-day
        let earned = 0;
        streakPeriods.forEach(p => {
            if (p.days >= 90) earned += 6; // 1+2+3
            else if (p.days >= 30) earned += 3; // 1+2
            else if (p.days >= 7) earned += 1;
        });
        // Load used count from localStorage
        let used = 0;
        if (typeof window !== 'undefined') {
            used = parseInt(localStorage.getItem('streak_freeze_used') || '0', 10);
        }
        const freezeCount = Math.min(5, Math.max(0, earned - used));

        return {
            periods: [...periods].reverse(),
            stats: { current, best, total: dates.length, avgStreak },
            readDatesSet,
            weeklyInsights: { thisWeekDays, lastWeekDays, bestWeekday, comebackCount },
            freezeCount,
        };
    }, [progress]);

    return (
        <div className="animate-in fade-in slide-in-from-right-4 duration-500 space-y-5">
            {/* Header */}
            <div className="flex items-center gap-3 px-2">
                <div className="p-2.5 rounded-2xl bg-gradient-to-br from-orange-500/20 to-red-500/10">
