                                <div className="p-2.5 rounded-2xl bg-cyan-500/10">
                                    <Snowflake size={20} className="text-cyan-500" />
                                </div>
                                <div>
                                    <p className="text-sm font-bold">연속 프리즈</p>
                                    <p className="text-[10px] text-muted-foreground mt-0.5">하루 쉬어도 연속이 유지됩니다</p>
