// === Heatmap Component ===
function HeatmapView({ readDatesSet }: { readDatesSet: Set<string> }) {
    const [selectedDate, setSelectedDate] = useState<string | null>(null);

    const { weeks, months } = useMemo(() => {
        const now = new Date();
        const year = now.getFullYear();
        const startDate = new Date(year, 0, 1);
        // Adjust to start on Sunday
        const startDay = startDate.getDay();

        const weeks: { date: string; read: boolean; day: number; month: number }[][] = [];
        let currentWeek: typeof weeks[0] = [];

        // Pad leading empty days
        for (let i = 0; i < startDay; i++) {
            currentWeek.push({ date: '', read: false, day: -1, month: -1 });
        }

        const endDate = new Date(year, 11, 31);
        const d = new Date(startDate);
        while (d <= endDate) {
            const dateStr = toDateStr(d);
            currentWeek.push({
                date: dateStr,
                read: readDatesSet.has(dateStr),
                day: d.getDate(),
                month: d.getMonth(),
            });
            if (currentWeek.length === 7) {
                weeks.push(currentWeek);
                currentWeek = [];
            }
            d.setDate(d.getDate() + 1);
        }
        if (currentWeek.length > 0) {
            while (currentWeek.length < 7) currentWeek.push({ date: '', read: false, day: -1, month: -1 });
            weeks.push(currentWeek);
        }

        // Month labels
        const months: { label: string; weekIndex: number }[] = [];
        const monthNames = ['1월', '2월', '3월', '4월', '5월', '6월', '7월', '8월', '9월', '10월', '11월', '12월'];
        let lastMonth = -1;
        weeks.forEach((week, weekIdx) => {
            const validDay = week.find(d => d.month >= 0);
            if (validDay && validDay.month !== lastMonth) {
                months.push({ label: monthNames[validDay.month], weekIndex: weekIdx });
                lastMonth = validDay.month;
            }
        });

        return { weeks, months };
    }, [readDatesSet]);

    const totalRead = useMemo(() => readDatesSet.size, [readDatesSet]);
    const selectedInfo = selectedDate && readDatesSet.has(selectedDate) ? '✅ 읽기 완료' : selectedDate ? '⬜ 미완료' : null;

    return (
        <div className="space-y-4">
            {/* Legend */}
            <div className="flex items-center justify-between px-1">
                <span className="text-xs font-bold text-muted-foreground">
                    {new Date().getFullYear()}년 — {totalRead}일 읽기 완료
                </span>
                <div className="flex items-center gap-1 text-[9px] text-muted-foreground">
                    <span>적음</span>
                    <div className="w-3 h-3 rounded-[3px] bg-muted/30" />
                    <div className="w-3 h-3 rounded-[3px] bg-emerald-300/40" />
                    <div className="w-3 h-3 rounded-[3px] bg-emerald-500/70" />
                    <div className="w-3 h-3 rounded-[3px] bg-emerald-600" />
                    <span>많음</span>
                </div>
            </div>

            {/* Selected Date Info */}
            {selectedDate && (
                <div className="text-center py-1">
                    <span className="text-xs font-bold text-foreground">
                        {formatDateFull(selectedDate)} — {selectedInfo}
                    </span>
                </div>
            )}

            {/* Heatmap Grid */}
            <div
                className="overflow-x-auto -mx-4 px-4 no-scrollbar"
                onTouchStart={(e) => e.stopPropagation()}
                onTouchMove={(e) => e.stopPropagation()}
                onTouchEnd={(e) => e.stopPropagation()}
            >
                <div style={{ minWidth: `${weeks.length * 14 + 30}px` }}>
                    {/* Month labels */}
                    <div className="flex mb-1 ml-[26px]">
                        {months.map((m, i) => (
                            <div
                                key={i}
                                className="text-[8px] text-muted-foreground font-medium absolute"
                                style={{ left: `${m.weekIndex * 14 + 30}px` }}
                            >
                                {m.label}
                            </div>
                        ))}
                    </div>
                    <div className="relative pt-3">
                        {/* Day labels */}
                        <div className="absolute left-0 top-3 flex flex-col gap-[2px]">
                            {['', '월', '', '수', '', '금', ''].map((l, i) => (
                                <div key={i} className="h-[10px] text-[8px] text-muted-foreground/60 leading-[10px]">
                                    {l}
                                </div>
                            ))}
                        </div>
                        {/* Grid */}
                        <div className="flex gap-[2px] ml-[22px]">
                            {weeks.map((week, wi) => (
                                <div key={wi} className="flex flex-col gap-[2px]">
                                    {week.map((day, di) => {
                                        if (!day.date) return <div key={di} className="w-[10px] h-[10px]" />;
                                        const isToday = day.date === toDateStr(new Date());
                                        return (
                                            <div
                                                key={di}
                                                onClick={() => setSelectedDate(day.date)}
                                                className={cn(
                                                    "w-[10px] h-[10px] rounded-[2px] cursor-pointer transition-all",
                                                    day.read
                                                        ? "bg-emerald-500 dark:bg-emerald-400"
                                                        : "bg-muted/30 dark:bg-white/5",
                                                    isToday && "ring-1 ring-foreground/30",
                                                    selectedDate === day.date && "ring-2 ring-primary"
                                                )}
                                                title={`${day.date} ${day.read ? '읽음' : '미완료'}`}
                                            />
                                        );
                                    })}
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

// === Insight Row ===
function InsightRow({ emoji, text, highlight }: { emoji: string; text: string; highlight?: boolean }) {
    return (
        <div className="flex items-center gap-2.5">
            <span className="text-sm">{emoji}</span>
            <span className={cn(
                "text-xs font-medium",
                highlight ? "text-foreground font-bold" : "text-muted-foreground"
            )}>
                {text}
            </span>
        </div>
    );
}

// === Stat Card ===
function StatCard({ icon: Icon, iconColor, iconBg, label, value, highlight }: {
    icon: any; iconColor: string; iconBg: string; label: string; value: string; highlight?: boolean;
}) {
    return (
        <SmartCard variant="elevated" className={cn(
            "border dark:border-white/10",
            highlight && "border-amber-500/20 bg-gradient-to-br from-amber-500/5 to-transparent dark:border-amber-500/30"
        )}>
            <div className="flex items-center gap-3">
                <div className={cn("p-2 rounded-xl", iconBg)}>
                    <Icon size={16} className={iconColor} />
                </div>
                <div>
                    <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">{label}</p>
                    <p className="text-xl font-display font-bold">{value}</p>
                </div>
            </div>
        </SmartCard>
    );
}

