"use client";

import { useState } from "react";
import { Flame, Trophy, Share2 } from "lucide-react";
import dynamic from 'next/dynamic';
import { cn } from "@/lib/utils";
import DashboardGrid, { GridCell } from "../layout/DashboardGrid";
import { SmartCard } from "../ui/smart-card";
import DateNavigator from "../DateNavigator";
import BibleCard from "../BibleCard";
import { EncouragementBanner } from "../EncouragementBanner";
import { BibleReadingPlan } from "@/types/bible";

const YoutubePlayer = dynamic(() => import("../YoutubePlayer"), {
    loading: () => <div className="h-48 w-full bg-muted/20 animate-pulse rounded-3xl" />,
    ssr: false
});

interface HomeTabProps {
    selectedDate: string;
    onDateChange: (date: string) => void;
    onShare: () => void;
    onTextClick?: () => void;
    targetPlan: BibleReadingPlan | null;
    isCompleted: boolean;
    onTogglePlan: (id: number) => void;
    videoDuration: number | null;
    fontSize: 'small' | 'medium' | 'large';
    streak: number;
    progressPercent: number;
    daysLeft: number;
    autoPlay: boolean;
    showEncouragement: boolean;
    onTabChange: (tab: any) => void;
    streakDisplayMode?: 'day' | 'progress';
}

export default function HomeTab({
    selectedDate,
    onDateChange,
    onShare,
    onTextClick,
    targetPlan,
    isCompleted,
    onTogglePlan,
    videoDuration,
    fontSize,
    streak,
    progressPercent,
    daysLeft,
    autoPlay,
    showEncouragement,
    onTabChange,
    streakDisplayMode = 'day'
}: HomeTabProps) {
    const [isFocused, setIsFocused] = useState(false);

    return (
        <div className="relative min-h-[85vh] animate-in fade-in duration-500 overflow-visible">
            {/* Aurora Background */}
            <div className={cn(
                "fixed inset-0 pointer-events-none transition-opacity duration-1000 z-0",
                isFocused ? "opacity-100" : "opacity-30"
            )}>
                <div className="absolute top-[-10%] left-[-10%] w-[70vw] h-[70vw] rounded-full bg-blue-400/20 max-w-[500px] max-h-[500px] blur-[80px] mix-blend-multiply dark:mix-blend-screen transition-all duration-[3000ms] animate-pulse" />
                <div className="absolute top-[20%] right-[-10%] w-[60vw] h-[60vw] rounded-full bg-emerald-400/20 max-w-[400px] max-h-[400px] blur-[80px] mix-blend-multiply dark:mix-blend-screen transition-all duration-[4000ms] animate-pulse delay-75" />
                <div className="absolute bottom-[-10%] left-[20%] w-[80vw] h-[80vw] rounded-full bg-purple-400/20 max-w-[600px] max-h-[600px] blur-[100px] mix-blend-multiply dark:mix-blend-screen transition-all duration-[5000ms] animate-pulse delay-150" />
            </div>

            <div className={cn(
                "relative z-10 transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)]",
                isFocused ? "-translate-y-2 lg:-translate-y-6" : ""
            )}>
                {/* Absolute Backdrop for Focus Mode to hide GridCell content behind BibleCard */}
                {isFocused && (
                    <div
                        className="fixed inset-0 bg-background/60 backdrop-blur-md z-40 transition-opacity duration-700 opacity-100"
                        onClick={() => setIsFocused(false)}
                    />
                )}

                <DashboardGrid>
                    {/* Date Navigation */}
                    <GridCell span="3" className={cn("transition-all duration-500", isFocused ? "opacity-0 h-0 overflow-hidden mb-0" : "opacity-100 mb-2")}>
                        <DateNavigator
                            currentDate={selectedDate}
                            onDateChange={onDateChange}
                        />
                    </GridCell>

                    <GridCell span="3" className="relative z-50">
                        {targetPlan ? (
                            <BibleCard
                                plan={targetPlan}
                                isCompleted={isCompleted}
                                onToggle={() => onTogglePlan(targetPlan.id)}
                                onTextClick={onTextClick}
                                videoDuration={videoDuration}
                                fontSize={fontSize}
                                streakDisplayMode={streakDisplayMode}
                                isFocused={isFocused}
                                onFocusToggle={() => setIsFocused(!isFocused)}
                            />
                        ) : (
                            <SmartCard variant="outline" className="p-12 text-center text-muted-foreground shadow-sm">
                                이 날의 읽기표가 없습니다.
                            </SmartCard>
                        )}
                    </GridCell>

                    {/* Audio Bible */}
                    <GridCell span="3" className={cn("space-y-4 transition-all duration-700", isFocused ? "opacity-0 pointer-events-none translate-y-4" : "opacity-100 translate-y-0")}>
                        <div className="flex items-center gap-2 mb-2">
                            <div className="w-6 h-6 rounded-lg bg-red-600 flex items-center justify-center shadow-lg">
                                <Flame className="w-3 h-3 text-white fill-current" />
                            </div>
                            <h3 className="text-xs font-bold text-muted-foreground uppercase tracking-widest">오늘의 말씀 영상</h3>
                        </div>
                        <YoutubePlayer selectedDate={selectedDate} autoPlay={autoPlay} />
                    </GridCell>

                    {/* Stats Slider */}
                    <GridCell span="3" className={cn("overflow-hidden transition-all duration-700", isFocused ? "opacity-0 pointer-events-none translate-y-4" : "opacity-100 translate-y-0")}>
                        <div
                            className="flex gap-3 overflow-x-auto pb-4 -mx-4 px-4 snap-x no-scrollbar"
                            onTouchStart={(e) => e.stopPropagation()}
                            onTouchMove={(e) => e.stopPropagation()}
                            onTouchEnd={(e) => e.stopPropagation()}
                        >
                            {/* Streak Card */}
                            <div className="min-w-[30%] flex-1 snap-start" onClick={() => onTabChange("streak")}>
                                <SmartCard
                                    variant="elevated"
                                    className="h-full flex flex-col justify-between cursor-pointer hover:border-orange-500/30 transition-colors group p-4"
                                >
                                    <div className="flex justify-between items-start mb-2">
                                        <span className="text-[9px] font-bold uppercase tracking-widest text-muted-foreground group-hover:text-orange-500 transition-colors">연속 읽기</span>
                                        <Flame size={14} className="text-orange-500" />
                                    </div>
                                    <div>
                                        <span className="text-xl font-display font-medium">{streak}</span>
                                        <span className="text-[10px] text-muted-foreground ml-1">
                                            {streakDisplayMode === 'progress' ? '/365일' : '일차'}
                                        </span>
                                    </div>
                                </SmartCard>
                            </div>

                            {/* Progress Card */}
                            <div className="min-w-[30%] flex-1 snap-start" onClick={() => onTabChange("record")}>
                                <SmartCard
                                    variant="elevated"
                                    className="h-full flex flex-col justify-between cursor-pointer hover:border-primary/30 transition-colors group p-4"
                                >
                                    <div className="flex justify-between items-start mb-2">
                                        <span className="text-[9px] font-bold uppercase tracking-widest text-muted-foreground group-hover:text-primary transition-colors">진행률</span>
                                        <Trophy size={14} className="text-primary" />
                                    </div>
                                    <div>
                                        <span className="text-xl font-display font-medium">{progressPercent}%</span>
                                        <span className="text-[10px] text-muted-foreground ml-1">완료</span>
                                    </div>
                                </SmartCard>
                            </div>

                            {/* Remaining Days Card */}
                            <div className="min-w-[30%] flex-1 snap-start" onClick={() => onTabChange("record")}>
                                <SmartCard
                                    variant="elevated"
                                    className="h-full flex flex-col justify-between cursor-pointer hover:border-primary/30 transition-colors group p-4"
                                >
                                    <div className="flex justify-between items-start mb-2">
                                        <span className="text-[9px] font-bold uppercase tracking-widest text-muted-foreground group-hover:text-primary transition-colors">남은 기간</span>
                                    </div>
                                    <div>
                                        <span className="text-xl font-display font-medium">{daysLeft}</span>
                                        <span className="text-[10px] text-muted-foreground ml-1">일</span>
                                    </div>
                                </SmartCard>
                            </div>
                        </div>
                    </GridCell>

                    {/* Encouragement */}
                    {showEncouragement && (
                        <GridCell span="3" className={cn("transition-all duration-700", isFocused ? "opacity-0 pointer-events-none translate-y-4" : "opacity-100 translate-y-0")}>
                            <EncouragementBanner
                                streak={streak}
                                progressPercent={progressPercent}
                                dayOfYear={targetPlan?.day_of_year || 1}
                            />
                        </GridCell>
                    )}
                </DashboardGrid>
            </div>
        </div>
    );
}

"use client";

import { useMemo } from "react";
import { ArrowLeft, Leaf, Crown, BookOpen, Star, Sparkles } from "lucide-react";
import { BibleReadingPlan } from "@/types/bible";
import { getOfficialCategory } from "@/lib/bible-utils";
import { calculateStreak } from "@/lib/stats";

interface StatsTabProps {
    completedPlanIds: number[];
    allPlans: BibleReadingPlan[];
    onBack: () => void;
}

export default function StatsTab({ completedPlanIds, allPlans, onBack }: StatsTabProps) {
    const stats = useMemo(() => {
        const completedDates = allPlans
            .filter(p => completedPlanIds.includes(p.id))
            .map(p => p.date)
            .filter((d): d is string => !!d);

        const streak = calculateStreak(completedDates);

        // Calculate most read category
        const categoryCounts: Record<string, number> = {};
        allPlans
            .filter(p => completedPlanIds.includes(p.id))
            .forEach(p => {
                const cat = p.category || getOfficialCategory(p.verses);
                if (cat) {
                    categoryCounts[cat] = (categoryCounts[cat] || 0) + 1;
                }
            });

        let mostReadCat = "아직 읽은 말씀이 없습니다";
        let maxCount = 0;
        Object.entries(categoryCounts).forEach(([cat, count]) => {
            if (count > maxCount) {
                mostReadCat = cat;
                maxCount = count;
            }
        });

        // Determine Level
        const readCnt = completedPlanIds.length;
        let stage = 0; // Seed
        let stageName = "말씀의 씨앗";
        let nextGoal = 10;

        if (readCnt >= 300) { stage = 4; stageName = "생명 나무"; nextGoal = 365; }
        else if (readCnt >= 100) { stage = 3; stageName = "푸른 나무"; nextGoal = 300; }
        else if (readCnt >= 30) { stage = 2; stageName = "작은 묘목"; nextGoal = 100; }
        else if (readCnt >= 10) { stage = 1; stageName = "새싹"; nextGoal = 30; }

        const progressToNext = Math.min(100, Math.round((readCnt / nextGoal) * 100));

        return { streak, mostReadCat, readCnt, stage, stageName, nextGoal, progressToNext };
    }, [completedPlanIds, allPlans]);

    return (
        <div className="h-full flex flex-col bg-background/50 relative">
            {/* Header */}
            <div className="sticky top-0 z-10 bg-background/80 backdrop-blur-md px-4 py-4 flex items-center justify-between border-b border-border/50">
                <button
                    onClick={onBack}
                    className="p-2 -ml-2 rounded-full hover:bg-secondary/80 transition-colors"
                >
                    <ArrowLeft className="w-6 h-6 text-foreground" />
                </button>
                <div className="px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20 text-emerald-600 dark:text-emerald-400 font-bold text-xs tracking-wide">
                    {stats.stageName}
                </div>
            </div>

            <div className="flex-1 overflow-y-auto pb-32">
                {/* Hero Tree Visual */}
                <div className="relative w-full h-[320px] bg-gradient-to-b from-blue-50/50 to-emerald-50/50 dark:from-blue-950/20 dark:to-emerald-950/20 overflow-hidden border-b border-border/50 shadow-sm flex flex-col justify-end pb-4 pt-10">

                    {/* Background decorations for depth */}
                    <div className="absolute top-10 left-10 w-32 h-32 bg-yellow-300/20 rounded-full blur-3xl blend-screen" />
                    <div className="absolute top-20 right-10 w-40 h-40 bg-emerald-400/10 rounded-full blur-3xl blend-screen" />

                    <h2 className="absolute top-8 left-0 right-0 text-center text-3xl font-serif font-black tracking-tight text-foreground/80 z-20">
                        영적 여정
                    </h2>

                    <div className="relative w-full h-[200px] z-10">
                        <SpiritualTree stage={stats.stage} />
                    </div>
                </div>

                {/* Progress Bar (Next Level) */}
                <div className="px-6 -mt-6 relative z-20">
                    <div className="bg-card p-5 rounded-3xl shadow-lg border border-border/60">
                        <div className="flex justify-between items-end mb-2">
                            <h4 className="text-sm font-bold text-foreground">성장 지수</h4>
                            <span className="text-xs font-semibold text-emerald-600 dark:text-emerald-400">
                                {stats.readCnt} / {stats.nextGoal} 장
                            </span>
                        </div>
                        <div className="h-3 w-full bg-secondary rounded-full overflow-hidden">
                            <div
                                className="h-full bg-gradient-to-r from-emerald-400 to-green-500 rounded-full transition-all duration-1000 ease-out"
                                style={{ width: `${stats.progressToNext}%` }}
                            />
                        </div>
                        <p className="text-[10px] text-muted-foreground mt-2 text-center text-balance font-medium">
                            말씀을 매일 읽을수록 당신의 영적 나무는 더욱 크고 아름답게 자라납니다.
                        </p>
                    </div>
                </div>

                {/* 은혜의 발자취 (Insight Timeline) */}
                <div className="px-5 mt-10">
                    <h3 className="text-lg font-bold font-serif mb-5 flex items-center gap-2">
                        <Sparkles className="w-5 h-5 text-amber-500 ml-1" />
                        은혜의 발자취
                    </h3>
                    <div className="space-y-3">
                        <InsightCard
                            icon={<BookOpen className="w-5 h-5 text-blue-500" />}
                            title="가장 많이 읽은 주제/성경"
                            value={stats.mostReadCat}
                            desc="당신의 마음이 머문 곳"
                        />
                        <InsightCard
                            icon={<Crown className="w-5 h-5 text-amber-500" />}
                            title="누적 말씀 묵상"
                            value={`${stats.readCnt} 장`}
                            desc={`일독(365장)까지 ${Math.max(0, 365 - stats.readCnt)}장 남음`}
                        />
                        <InsightCard
                            icon={<Star className="w-5 h-5 text-purple-500" />}
                            title="현재 연속 묵상일"
                            value={`${stats.streak} 일`}
                            desc="꾸준함이 만드는 기적"
                        />
                    </div>
                </div>
            </div>
        </div>
    );
}

function InsightCard({ icon, title, value, desc }: any) {
    return (
        <div className="flex items-center gap-4 p-4 rounded-3xl bg-card border border-border/60 shadow-sm transition-all hover:bg-secondary/50">
            <div className="w-12 h-12 rounded-2xl bg-secondary/80 flex items-center justify-center shrink-0 border border-border/80 shadow-inner">
                {icon}
            </div>
            <div className="flex-1 min-w-0">
                <p className="text-[11px] font-semibold text-muted-foreground uppercase tracking-widest mb-0.5">{title}</p>
                <p className="font-black text-foreground text-lg tracking-tight truncate">{value}</p>
                <p className="text-xs text-muted-foreground mt-1 font-medium">{desc}</p>
            </div>
        </div>
    );
}

function SpiritualTree({ stage }: { stage: number }) {
    // Dynamic, animated SVG Tree visual
    return (
        <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl" strokeLinejoin="round" strokeLinecap="round">
            {/* Ground line */}
            <path d="M 20 180 Q 100 170 180 180" stroke="#a3e635" strokeWidth="3" fill="none" opacity="0.4" strokeDasharray="5, 5" />

            {stage === 0 && (
                <circle cx="100" cy="175" r="5" fill="#84cc16" className="animate-pulse shadow-xl" />
            )}

            {stage >= 1 && (
                <>
                    <path d="M 100 180 Q 95 160 100 150" stroke="#65a30d" strokeWidth="6" fill="none" />
                    <path d="M 100 165 C 80 160 85 145 100 150 C 115 145 120 160 100 165" fill="#a3e635" opacity={stage >= 1 ? 1 : 0} />
                </>
            )}

            {stage >= 2 && (
                <>
                    <path d="M 100 180 Q 90 120 100 90" stroke="#4d7c0f" strokeWidth="8" fill="none" />
                    <path d="M 98 130 Q 70 110 80 90" stroke="#4d7c0f" strokeWidth="5" fill="none" />
                    <path d="M 102 140 Q 130 120 120 100" stroke="#4d7c0f" strokeWidth="5" fill="none" />
                    {/* Canopy bubbles */}
                    <circle cx="80" cy="90" r="18" fill="#65a30d" opacity="0.95" />
                    <circle cx="120" cy="100" r="16" fill="#65a30d" opacity="0.95" />
                    <circle cx="100" cy="80" r="24" fill="#a3e635" opacity="1" />
                </>
            )}

            {stage >= 3 && (
                <>
                    <path d="M 95 180 Q 80 80 100 50" stroke="#3f6212" strokeWidth="16" fill="none" />
                    <path d="M 92 120 Q 50 90 60 60" stroke="#3f6212" strokeWidth="8" fill="none" />
                    <path d="M 105 130 Q 150 100 140 70" stroke="#3f6212" strokeWidth="8" fill="none" />

                    {/* Big Leaves */}
                    <circle cx="60" cy="60" r="30" fill="#4d7c0f" opacity="0.9" />
                    <circle cx="140" cy="70" r="28" fill="#4d7c0f" opacity="0.9" />
                    <circle cx="95" cy="45" r="42" fill="#65a30d" opacity="0.95" />
                    <circle cx="80" cy="30" r="24" fill="#a3e635" opacity="0.8" />
                    <circle cx="120" cy="40" r="30" fill="#84cc16" opacity="0.85" />

                    {/* Glow */}
                    <circle cx="100" cy="40" r="60" fill="#d9f99d" opacity="0.1" className="animate-pulse" />
                </>
            )}

            {stage >= 4 && (
                <>
                    {/* Fruit / Apples / Blessing Orbs */}
                    <circle cx="70" cy="50" r="5" fill="#f43f5e" />
                    <circle cx="130" cy="60" r="6" fill="#f43f5e" />
                    <circle cx="100" cy="25" r="5" fill="#f43f5e" />
                    <circle cx="110" cy="80" r="6" fill="#f43f5e" />
                    <circle cx="55" cy="80" r="5" fill="#f43f5e" />
                    {/* Brighter Glow */}
                    <circle cx="100" cy="50" r="80" fill="#fef08a" opacity="0.15" />
                </>
            )}
        </svg>
    );
}

