import { useState, useEffect } from 'react';

export interface BibleSettings {
    fontSize: number;
    lineHeight: number;
    theme: 'system' | 'light' | 'dark' | 'sepia';
    fontFamily: 'serif' | 'sans' | 'system';
    livingTypography: boolean;
}

const DEFAULT_SETTINGS: BibleSettings = {
    fontSize: 18,
    lineHeight: 2.2,
    theme: 'system',
    fontFamily: 'serif',
    livingTypography: true,
};

export function useBibleSettings() {
    const [settings, setSettings] = useState<BibleSettings>(DEFAULT_SETTINGS);
    const [isLoaded, setIsLoaded] = useState(false);

    // Load from local storage on mount
    useEffect(() => {
        const saved = localStorage.getItem('rb_bible_settings');
        if (saved) {
            try {
                setSettings({ ...DEFAULT_SETTINGS, ...JSON.parse(saved) });
            } catch (e) {
                console.error("Failed to parse bible settings", e);
            }
        }
        setIsLoaded(true);
    }, []);

    // Save to local storage on change
    useEffect(() => {
        if (isLoaded) {
            localStorage.setItem('rb_bible_settings', JSON.stringify(settings));
        }
    }, [settings, isLoaded]);

    const updateSettings = (updates: Partial<BibleSettings>) => {
        setSettings(prev => ({ ...prev, ...updates }));
    };

    return { settings, updateSettings, isLoaded };
}

import { useState, useMemo, useRef, useCallback } from "react";

export type Tab = "home" | "streak" | "record" | "group" | "achievement" | "menu" | "hymn";

export function useDashboardNav() {
    const [activeTab, setBaseActiveTab] = useState<Tab>("home");

    const setActiveTab = useCallback((tab: Tab) => {
        setBaseActiveTab(tab);
        if (typeof window !== "undefined") {
            window.scrollTo({ top: 0, behavior: "instant" });
        }
    }, []);

    // Swipe navigation logic
    const tabOrder = useMemo<Tab[]>(() => ["home", "streak", "record", "achievement", "hymn", "group", "menu"], []);
    const touchStartX = useRef<number>(0);
    const touchStartY = useRef<number>(0);

    const handleTouchStart = useCallback((e: React.TouchEvent) => {
        touchStartX.current = e.touches[0].clientX;
        touchStartY.current = e.touches[0].clientY;
    }, []);

    const handleTouchEnd = useCallback((e: React.TouchEvent) => {
        const deltaX = e.changedTouches[0].clientX - touchStartX.current;
        const deltaY = e.changedTouches[0].clientY - touchStartY.current;

        if (Math.abs(deltaX) > 60 && Math.abs(deltaX) > Math.abs(deltaY) * 1.5) {
            if (activeTab === 'menu') return;

            const currentIndex = tabOrder.indexOf(activeTab);
            if (deltaX < 0 && currentIndex < tabOrder.length - 1) {
                setActiveTab(tabOrder[currentIndex + 1]);
            } else if (deltaX > 0 && currentIndex > 0) {
                setActiveTab(tabOrder[currentIndex - 1]);
            }
        }
    }, [activeTab, tabOrder]);

    return {
        activeTab,
        setActiveTab,
        handleTouchStart,
        handleTouchEnd
    };
}

