import { CapacitorHttp } from '@capacitor/core';

async function fetchChapterFromRemote(book: string, chapter: number, version: string): Promise<string[]> {
    const abbr = KOR_BOOK_MAP[book];
    const chapterLabel = book === '시편' ? '편' : '장';

    if (!abbr) return fallbackMock(book, chapter, version, chapterLabel);

    const langCode = version === 'KRV' ? 'kor' : 'eng-kjv';
    const originalUrl = `https://ibibles.net/quote.php?${langCode}-${abbr}/${chapter}:1-200`;

    try {
        let rawHtml = '';

        try {
            // Try Native Context (Bypasses CORS usually via plugin)
            const response = await CapacitorHttp.request({
                method: 'GET',
                url: originalUrl
            });
            rawHtml = response.data as string;

            // If native returns nothing/fails somewhat silently, fallback
            if (!rawHtml) throw new Error('Empty native response');
        } catch (nativeErr) {
            // Fallback to CORS proxy (mainly for dev web)
            console.log('Native HTTP failed or unavailable, using CORS proxy...', nativeErr);
            const proxyUrl = `https://api.allorigins.win/raw?url=${encodeURIComponent(originalUrl)}`;
            const res = await fetch(proxyUrl);
            if (!res.ok) throw new Error('Proxy Network error');
            rawHtml = await res.text();
        }

        const verses: string[] = [];
        const regex = /<small>\d+:\d+<\/small>(.*?)<br>/g;
        let match;

        while ((match = regex.exec(rawHtml)) !== null) {
            // Strip any remaining internal tags just in case
            let cleanText = match[1].replace(/<[^>]*>?/gm, '').trim();
            verses.push(cleanText);
        }

        if (verses.length > 0) {
            return verses;
        } else {
            return fallbackMock(book, chapter, version, chapterLabel);
        }
    } catch (e) {
        console.warn("Failed fetching from ibibles, using mock data", e);
        return fallbackMock(book, chapter, version, chapterLabel);
    }
}

function fallbackMock(book: string, chapter: number, version: string, chapterLabel: string): string[] {
    const verses: string[] = [];
    for (let i = 1; i <= 25; i++) {
        if (version === 'KRV') {
            verses.push(`[DB 접근지연] ${book} ${chapter}${chapterLabel} ${i}절 말씀입니다. (오프라인 캐싱 또는 네트워크 문제)`);
        } else {
            verses.push(`In the beginning God created the heavens and the earth. (${book} ${chapter}:${i})`);
        }
    }
    return verses;
}

import { BIBLE_BOOKS, BibleCategory, CHAPTER_KEYWORDS } from "./bible-metadata";

/**
 * 성경 구절 목록(verses)으로부터 공식 분류를 추출합니다.
 */
export function getOfficialCategory(verses: string[]): string {
    if (!verses || verses.length === 0) return "분류 정보 없음";

    const categories = new Set<string>();

    verses.forEach(v => {
        // "창세기 1장" 형식에서 책 이름 추출
        const bookName = v.split(' ')[0];
        const book = BIBLE_BOOKS.find(b => b.name === bookName);
        if (book) {
            categories.add(book.subCategory);
        }
    });

    return Array.from(categories).join(' / ');
}

/**
 * 성경 구절로부터 요약 키워드(해시태그)를 장별(Chapter) 핵심 내용 기반으로 생성합니다.
 */
/**
 * 성경 구절로부터 요약 키워드(해시태그)를 장별(Chapter) 핵심 내용 기반으로 생성합니다.
 * UI 렌더링을 위해 구조화된 데이터를 반환합니다.
 */
export function generateStructuredKeywords(verses: string[]): { text: string; isPsalm: boolean }[] {
    if (!verses || verses.length === 0) return [{ text: "#말씀", isPsalm: false }, { text: "#묵상", isPsalm: false }];

    const keywords = new Map<string, boolean>(); // Key: keyword, Value: isPsalm

    verses.forEach(v => {
        const parts = v.split(' ');
        if (parts.length < 2) return;

        const bookName = parts[0];
        const isPsalm = bookName === '시편';
        const chapterPart = parts[1].replace('장', '');

        // 장 번호 추출 (범위일 경우 첫 장 기준)
        const chapterNum = parseInt(chapterPart.split('-')[0]);

        // 1. 장별 정밀 키워드 확인
        const chapterData = CHAPTER_KEYWORDS[bookName]?.[chapterNum];
        if (chapterData) {
            chapterData.forEach(k => keywords.set(k, isPsalm));
        } else {
            // 2. 장별 데이터 없을 시 책 단위 키워드 폴백
            const book = BIBLE_BOOKS.find(b => b.name === bookName);
            if (book) {
                book.keywords.forEach(k => keywords.set(k, isPsalm));
            }
        }
    });

    // 일반 단어 블랙리스트 필터
    const KEYWORD_BLACKLIST = new Set([
        '짐승', '사람', '물', '땅', '집', '아들', '딸', '아버지',
        '날', '밤', '말', '손', '눈', '입', '피', '길', '왕', '성',
        '문', '옷', '불', '뜻', '배', '밭', '양', '소', '나무'
    ]);

    // 최종 해시태그 생성 (블랙리스트 제외, 최대 6개)
    return Array.from(keywords.entries())
        .filter(([k]) => !KEYWORD_BLACKLIST.has(k))
        .slice(0, 6)
        .map(([k, isPsalm]) => ({ text: `#${k}`, isPsalm }));
}

/**
 * 하위 호환성을 위한 문자열 반환 함수
 */
export function generateKeywords(verses: string[]): string {
    return generateStructuredKeywords(verses).map(k => k.text).join(' ');
}

/**
 * 성경 구절 분량을 계산하여 1분 단위 초정밀 시간을 산출합니다.
 * 권별 분량 가중치를 적용하여 형평성 있는 시간을 제공합니다.
 */
export function calculateReadingTime(verses: string[]): string {
    if (!verses || verses.length === 0) return "오늘의 읽기, 약 1분 소요";

    let totalMinutes = 0;

    verses.forEach(v => {
        const parts = v.split(' ');
        if (parts.length < 2) return;

        const bookName = parts[0];
        const book = BIBLE_BOOKS.find(b => b.name === bookName);
        const weight = book?.readingWeight || 1.0;

        const chapterPart = parts[1].replace('장', '');
        let count = 1;

        if (chapterPart.includes('-')) {
            const [start, end] = chapterPart.split('-').map(Number);
            if (!isNaN(start) && !isNaN(end)) {
                count = end - start + 1;
            }
        }

        // 장당 기준 시간(3.2분) * 권별 가중치 * 장 수
        totalMinutes += (3.2 * weight * count);
    });

    const finalMinutes = Math.max(1, Math.round(totalMinutes));
    return `오늘의 읽기, 약 ${finalMinutes}분 소요`;
}

// Simple substitution cipher + Base64 for invite codes
// We don't want heavy crypto libs on client side if possible, but for "High-End", we should use Web Crypto API.
// However, to keep invite codes short and URL-friendly, a custom obfuscation or lightweight encryption is better.
// Given constraints, I will implement a robust reversible obfuscator.

const CHAR_MAP = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
const SHIFT = 7; // Caesar shift for simple obscurity

export function encryptInviteCode(groupId: string): string {
    // 1. Text to Base64 to handle any chars
    const base64 = btoa(encodeURIComponent(groupId));

    // 2. Simple Caesar Shift on the Base64 string to avoid obvious format
    let result = "";
    for (let i = 0; i < base64.length; i++) {
        const char = base64[i];
        const code = char.charCodeAt(0);
        result += String.fromCharCode(code + SHIFT);
    }

    // 3. URL Safe replacement
    return result.replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
}

export function decryptInviteCode(code: string): string | null {
    try {
        // 1. Restore URL Safe chars
        let recovered = code.replace(/-/g, '+').replace(/_/g, '/');

        // 2. Reverse Caesar Shift
        let base64 = "";
        for (let i = 0; i < recovered.length; i++) {
            const char = recovered[i];
            const codePoint = char.charCodeAt(0);
            base64 += String.fromCharCode(codePoint - SHIFT);
        }

        // 3. Base64 to Text
        return decodeURIComponent(atob(base64));
    } catch (e) {
        console.error("Invalid Invite Code", e);
        return null;
    }
}

import planData from '../../plan.json';
import { BibleReadingPlan } from '@/types/bible';
